function createEmptyCustomContentState() {
  return {
    subjectsById: {},
    lessonsBySubjectGrade: {},
    quizzesByKey: {},
    loaded: false,
  };
}

function createEmptyPublishedContentState() {
  return {
    lessonsBySubjectGrade: {},
    quizzesByKey: {},
    loaded: false,
  };
}

function normalizeCustomContentSnapshot(snapshot = {}) {
  const nextState = createEmptyCustomContentState();
  const subjects = Array.isArray(snapshot?.subjects) ? snapshot.subjects : [];
  const lessons = Array.isArray(snapshot?.lessons) ? snapshot.lessons : [];
  const quizzes = Array.isArray(snapshot?.quizzes) ? snapshot.quizzes : [];
  subjects.forEach((record) => {
    const subjectId = String(record?.id || record?.subjectId || record?.subject || "").trim().toLowerCase();
    if (!subjectId) return;
    nextState.subjectsById[subjectId] = {
      id: subjectId,
      name: String(record?.name || record?.title || subjectId).trim() || subjectId,
      nameUr: String(record?.nameUr || record?.titleUr || record?.name || subjectId).trim() || subjectId,
      icon: String(record?.icon || "📘").trim() || "📘",
      color: String(record?.color || "#38BDF8").trim() || "#38BDF8",
      __customSubject: true,
    };
  });
  lessons.forEach((record) => {
    const subject = String(record?.subject || "").trim();
    const grade = Number(record?.grade);
    const lessonKey = String(record?.lessonKey || record?.data?.key || record?.data?.id || "").trim();
    if (!subject || !Number.isFinite(grade) || !lessonKey || !record?.data) return;
    const bucketKey = `${subject}::${grade}`;
    if (!nextState.lessonsBySubjectGrade[bucketKey]) nextState.lessonsBySubjectGrade[bucketKey] = [];
    nextState.lessonsBySubjectGrade[bucketKey].push({
      ...record.data,
      key: record.data.key || lessonKey,
      id: record.data.id || `${subject}_${grade}_${lessonKey}`,
      __custom: true,
    });
  });
  quizzes.forEach((record) => {
    const subject = String(record?.subject || "").trim();
    const grade = Number(record?.grade);
    const lessonKey = String(record?.lessonKey || "").trim();
    if (!subject || !Number.isFinite(grade) || !lessonKey) return;
    nextState.quizzesByKey[`${subject}::${grade}::${lessonKey}`] = Array.isArray(record?.questions) ? record.questions : [];
  });
  nextState.loaded = true;
  return nextState;
}

function normalizeSubjectDefinition(subject = {}, fallback = {}) {
  const source = subject && typeof subject === "object" ? subject : {};
  const fallbackSource = fallback && typeof fallback === "object" ? fallback : {};
  const subjectId = String(source.id || source.subjectId || source.subject || fallbackSource.id || "").trim().toLowerCase();
  return {
    id: subjectId,
    name: String(source.name || source.title || fallbackSource.name || subjectId || "Custom Subject").trim() || "Custom Subject",
    nameUr: String(source.nameUr || source.titleUr || fallbackSource.nameUr || source.name || fallbackSource.name || subjectId || "کسٹم مضمون").trim() || "کسٹم مضمون",
    icon: String(source.icon || fallbackSource.icon || "📘").trim() || "📘",
    color: String(source.color || fallbackSource.color || "#38BDF8").trim() || "#38BDF8",
    __customSubject: Boolean(source.__customSubject || fallbackSource.__customSubject),
  };
}

function mergeSubjectCollections(baseSubjects = [], customSubjects = []) {
  const merged = new Map();
  (Array.isArray(baseSubjects) ? baseSubjects : []).forEach((subject) => {
    const normalized = normalizeSubjectDefinition(subject);
    if (!normalized.id) return;
    merged.set(normalized.id, normalized);
  });
  (Array.isArray(customSubjects) ? customSubjects : []).forEach((subject) => {
    const normalized = normalizeSubjectDefinition(subject, merged.get(String(subject?.id || "").trim().toLowerCase()) || {});
    if (!normalized.id) return;
    merged.set(normalized.id, normalized);
  });
  return Array.from(merged.values());
}

function mergeLessonCollections(baseLessons = [], customLessons = []) {
  const merged = new Map();
  (Array.isArray(baseLessons) ? baseLessons : []).forEach((lesson, index) => {
    const lessonKey = String(lesson?.key || lesson?.id || `built_in_${index}`).trim();
    if (!lessonKey) return;
    merged.set(lessonKey, lesson);
  });
  (Array.isArray(customLessons) ? customLessons : []).forEach((lesson, index) => {
    const lessonKey = String(lesson?.key || lesson?.id || `custom_${index}`).trim();
    if (!lessonKey) return;
    merged.set(lessonKey, lesson);
  });
  return Array.from(merged.values());
}

function buildPublishedLessonRuntimeKey(canonicalLessonKey, contentId) {
  const safeLessonKey = resolveCustomChapterLessonKey({ lessonKey: canonicalLessonKey, title: canonicalLessonKey });
  const suffix = String(contentId || "").trim().slice(0, 8) || "published";
  return `${safeLessonKey}__pub_${suffix}`;
}

function slugifyCustomChapterKey(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/['"`’]/g, "")
    .replace(/[^\p{L}\p{N}]+/gu, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 80);
}

function extractLessonOrdinal(...values) {
  for (const value of values) {
    const text = String(value || "").trim();
    if (!text) continue;
    const explicitMatch = text.match(/\b(?:lesson|chapter|سبق)\s*[_\-\s]?\s*(\d+)\b/iu);
    if (explicitMatch) {
      const ordinal = Number(explicitMatch[1]);
      if (Number.isFinite(ordinal) && ordinal > 0) return ordinal;
    }
    const plainMatch = text.match(/\b(\d+)\b/);
    if (plainMatch) {
      const ordinal = Number(plainMatch[1]);
      if (Number.isFinite(ordinal) && ordinal > 0) return ordinal;
    }
  }
  return null;
}

function resolveCustomChapterLessonKey({ lessonKey = "", title = "", fallbackNumber = null } = {}) {
  const ordinal = extractLessonOrdinal(lessonKey, title, fallbackNumber);
  if (Number.isFinite(ordinal) && ordinal > 0) return `lesson_${ordinal}`;
  const normalizedSlug = slugifyCustomChapterKey(lessonKey || title);
  return normalizedSlug || "lesson_1";
}

function cloneSerializableValue(value) {
  return JSON.parse(JSON.stringify(value == null ? null : value));
}

function stripRuntimeLessonMarkers(lesson = {}) {
  const nextLesson = cloneSerializableValue(lesson || {}) || {};
  delete nextLesson.__custom;
  delete nextLesson.__published;
  delete nextLesson.__contentId;
  delete nextLesson.__contentOwnerId;
  delete nextLesson.__publishedBy;
  delete nextLesson.__forkedFromContentId;
  delete nextLesson.__sourceLabel;
  return nextLesson;
}

function buildCustomChapterExportPayload({ subject, grade, lesson, questions, fallbackNumber = null }) {
  const lessonData = stripRuntimeLessonMarkers(lesson || {});
  delete lessonData.id;
  const canonicalLessonKey = lessonData?.publication?.canonicalLessonKey
    || lesson?.publication?.canonicalLessonKey
    || lessonData.key
    || getLessonKeyValue(lesson);
  const lessonKey = resolveCustomChapterLessonKey({
    lessonKey: canonicalLessonKey,
    title: lessonData.title || lesson?.title || "",
    fallbackNumber,
  });
  lessonData.key = lessonKey;
  return {
    kind: "homeschool-chapter",
    schemaVersion: 1,
    exportedAt: new Date().toISOString(),
    subject: String(subject || "").trim(),
    grade: Number(grade),
    lessonKey,
    lesson: lessonData,
    questions: Array.isArray(questions) ? cloneSerializableValue(questions) : [],
  };
}

function buildCustomChapterPackExportPayload({ subject, grade, subjectMeta = null, lessons = [], label = "" }) {
  const safeLessons = Array.isArray(lessons) ? lessons : [];
  const normalizedSubjectMeta = subjectMeta ? normalizeSubjectDefinition(subjectMeta) : null;
  return {
    kind: normalizedSubjectMeta ? "homeschool-subject-pack" : "homeschool-chapter-pack",
    schemaVersion: 1,
    exportedAt: new Date().toISOString(),
    subject: normalizedSubjectMeta ? {
      id: normalizedSubjectMeta.id,
      name: normalizedSubjectMeta.name,
      nameUr: normalizedSubjectMeta.nameUr,
      icon: normalizedSubjectMeta.icon,
      color: normalizedSubjectMeta.color,
    } : String(subject || "").trim(),
    grade: Number(grade),
    label: String(label || "").trim(),
    chapters: safeLessons.map((entry, index) => buildCustomChapterExportPayload({
      subject,
      grade,
      lesson: entry?.lesson,
      questions: entry?.questions,
      fallbackNumber: Number.isFinite(entry?.fallbackNumber) ? entry.fallbackNumber : index + 1,
    })),
  };
}

function normalizePublishedContentRows(rows = []) {
  const nextState = createEmptyPublishedContentState();
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const contentId = String(row?.content_id || row?.contentId || "").trim();
    const subject = String(row?.subject || "").trim();
    const grade = Number(row?.grade);
    const canonicalLessonKey = resolveCustomChapterLessonKey({
      lessonKey: row?.lesson_key || row?.lessonKey || row?.payload?.key || row?.payload?.title || "",
      title: row?.payload?.title || "",
    });
    const lessonPayload = stripRuntimeLessonMarkers(row?.payload || {});
    if (!contentId || !subject || !Number.isFinite(grade) || !lessonPayload || typeof lessonPayload !== "object") return;
    const runtimeKey = buildPublishedLessonRuntimeKey(canonicalLessonKey, contentId);
    const bucketKey = `${subject}::${grade}`;
    const authorUsername = String(row?.author_username || row?.authorUsername || "").trim();
    if (!nextState.lessonsBySubjectGrade[bucketKey]) nextState.lessonsBySubjectGrade[bucketKey] = [];
    nextState.lessonsBySubjectGrade[bucketKey].push({
      ...lessonPayload,
      key: runtimeKey,
      id: `published_${contentId}`,
      __published: true,
      __contentId: contentId,
      __contentOwnerId: String(row?.author_user_id || row?.authorUserId || "").trim(),
      __publishedBy: authorUsername,
      __forkedFromContentId: String(row?.forked_from_content_id || row?.forkedFromContentId || "").trim(),
      __sourceLabel: authorUsername ? `Published by ${authorUsername}` : "Published",
      publication: {
        contentId,
        canonicalLessonKey,
        authorUserId: String(row?.author_user_id || row?.authorUserId || "").trim(),
        authorUsername,
        publishedAt: Number(new Date(row?.published_at || row?.publishedAt || row?.updated_at || row?.updatedAt || Date.now()).getTime()) || Date.now(),
        updatedAt: Number(new Date(row?.updated_at || row?.updatedAt || Date.now()).getTime()) || Date.now(),
        forkedFromContentId: String(row?.forked_from_content_id || row?.forkedFromContentId || "").trim(),
        visibility: "published",
      },
    });
    nextState.quizzesByKey[`${subject}::${grade}::${runtimeKey}`] = Array.isArray(row?.questions) ? cloneSerializableValue(row.questions) : [];
  });
  nextState.loaded = true;
  return nextState;
}

function getLessonSourceLabel(lesson, language) {
  if (!lesson || typeof lesson !== "object") return "";
  if (lesson.__published) {
    const authorName = String(lesson?.publication?.authorUsername || lesson?.__publishedBy || "").trim();
    return joinLocalizedText(
      authorName ? `Published by ${authorName}` : "Published chapter",
      authorName ? `${authorName} کی شائع کردہ کاپی` : "شائع شدہ باب",
      language,
    );
  }
  if (lesson.__custom) {
    return joinLocalizedText(
      "Local custom chapter",
      "مقامی ذاتی باب",
      language,
    );
  }
  return "";
}

function normalizeChapterSourcePreferences(rawPreferences = {}) {
  const source = rawPreferences && typeof rawPreferences === "object" ? rawPreferences : {};
  return Object.entries(source).reduce((acc, [rawKey, rawValue]) => {
    const key = String(rawKey || "").trim();
    const value = rawValue && typeof rawValue === "object" ? rawValue : {};
    const mode = ["auto", "builtin", "custom", "published"].includes(value.mode) ? value.mode : "auto";
    if (!key) return acc;
    acc[key] = {
      mode,
      contentId: String(value.contentId || "").trim(),
      updatedAt: Number(value.updatedAt) || Date.now(),
    };
    return acc;
  }, {});
}

function buildChapterSourcePreferenceKey(subject, grade, canonicalLessonKey) {
  return `${String(subject || "").trim()}::${Number(grade)}::${resolveCustomChapterLessonKey({ lessonKey: canonicalLessonKey })}`;
}

function buildChapterAssignmentSlotKey(subject, grade, canonicalLessonKey, targetType = "grade", targetStudentEmail = "") {
  const safeTargetType = targetType === "student" ? "student" : "grade";
  const safeStudentEmail = safeTargetType === "student" ? String(targetStudentEmail || "").trim().toLowerCase() : "";
  return `${buildChapterSourcePreferenceKey(subject, grade, canonicalLessonKey)}::${safeTargetType}::${safeStudentEmail}`;
}

function toIsoDateString(value = Date.now()) {
  const date = value instanceof Date ? new Date(value.getTime()) : new Date(value);
  if (Number.isNaN(date.getTime())) return "";
  date.setHours(0, 0, 0, 0);
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function parseIsoDateValue(value) {
  const safe = String(value || "").trim();
  if (!safe) return null;
  const date = new Date(`${safe}T00:00:00`);
  return Number.isNaN(date.getTime()) ? null : date;
}

function getWeekStartDate(value = Date.now()) {
  const date = value instanceof Date ? new Date(value.getTime()) : new Date(value);
  if (Number.isNaN(date.getTime())) return null;
  date.setHours(0, 0, 0, 0);
  const day = date.getDay();
  const offset = day === 0 ? -6 : 1 - day;
  date.setDate(date.getDate() + offset);
  return date;
}

function getWeekDates(value = Date.now()) {
  const weekStart = getWeekStartDate(value);
  if (!weekStart) return [];
  return Array.from({ length: 7 }, (_, index) => {
    const date = new Date(weekStart.getTime());
    date.setDate(weekStart.getDate() + index);
    return toIsoDateString(date);
  });
}

function getSaturdayDate(value = Date.now()) {
  const weekDates = getWeekDates(value);
  return weekDates[5] || null;
}

function getAcademicWeekNumber(value = Date.now(), yearStartDate = null) {
  const currentWeekStart = getWeekStartDate(value);
  const academicStart = getWeekStartDate(yearStartDate || new Date(new Date(value).getFullYear(), 0, 1));
  if (!currentWeekStart || !academicStart) return 1;
  const diffMs = currentWeekStart.getTime() - academicStart.getTime();
  return Math.max(1, Math.floor(diffMs / (7 * 24 * 60 * 60 * 1000)) + 1);
}

function splitBalanced(items = [], groups = 1) {
  const safeItems = Array.isArray(items) ? items.slice() : [];
  const safeGroups = Math.max(1, Number(groups) || 1);
  if (!safeItems.length) return Array.from({ length: safeGroups }, () => []);
  const buckets = Array.from({ length: safeGroups }, () => []);
  let cursor = 0;
  safeItems.forEach((item) => {
    buckets[cursor].push(item);
    cursor = (cursor + 1) % safeGroups;
  });
  return buckets;
}

function normalizeTextArray(raw) {
  if (Array.isArray(raw)) {
    return raw
      .map((value) => String(value || "").trim())
      .filter(Boolean)
      .filter((value, index, list) => list.indexOf(value) === index);
  }
  const text = String(raw || "").trim();
  if (!text) return [];
  return text
    .split(/[,\n]+/)
    .map((value) => String(value || "").trim())
    .filter(Boolean)
    .filter((value, index, list) => list.indexOf(value) === index);
}

const AUTO_DIARY_ISO_DAY_OPTIONS = [
  { value: 1, en: "Monday", ur: "پیر" },
  { value: 2, en: "Tuesday", ur: "منگل" },
  { value: 3, en: "Wednesday", ur: "بدھ" },
  { value: 4, en: "Thursday", ur: "جمعرات" },
  { value: 5, en: "Friday", ur: "جمعہ" },
  { value: 6, en: "Saturday", ur: "ہفتہ" },
  { value: 7, en: "Sunday", ur: "اتوار" },
];

function normalizeAutoDiaryIsoDayList(raw, fallback = [1, 2, 3, 4, 5]) {
  const source = Array.isArray(raw) ? raw : normalizeTextArray(raw);
  const values = source
    .map((value) => Number(value))
    .filter((value) => Number.isFinite(value) && value >= 1 && value <= 7)
    .filter((value, index, list) => list.indexOf(value) === index)
    .sort((left, right) => left - right);
  const safeFallback = Array.isArray(fallback) ? fallback.filter((value) => Number.isFinite(Number(value))) : [1, 2, 3, 4, 5];
  return values.length ? values : safeFallback;
}

function normalizeAutoDiaryWeightMap(raw, validKeys = [], fallbackValue = 1, min = 0, max = 10) {
  const safeValidKeys = Array.isArray(validKeys) ? validKeys.map((value) => String(value || "").trim()).filter(Boolean) : [];
  const source = raw && typeof raw === "object" && !Array.isArray(raw) ? raw : {};
  return safeValidKeys.reduce((acc, key) => {
    const numericValue = Number(source[key]);
    acc[key] = Number.isFinite(numericValue)
      ? Math.min(max, Math.max(min, numericValue))
      : fallbackValue;
    return acc;
  }, {});
}

