function normalizeTestQuestionRecord(raw, index = 0) {
  if (!raw || typeof raw !== "object") return null;
  const type = ["mcq", "truefalse", "fillblank", "matching"].includes(String(raw.type || "").trim().toLowerCase())
    ? String(raw.type || "").trim().toLowerCase()
    : "mcq";
  const prompt = String(raw.prompt || raw.q || raw.question || "").trim();
  if (!prompt && type !== "matching") return null;
  if (type === "mcq") {
    const options = Array.isArray(raw.options || raw.a) ? (raw.options || raw.a).map((option) => String(option || "").trim()).filter(Boolean) : [];
    const correctIndex = Math.max(0, Math.min(options.length - 1, Number(raw.correctIndex ?? raw.c) || 0));
    if (!options.length) return null;
    return {
      id: String(raw.id || `question_${index}`).trim(),
      type,
      prompt,
      options,
      correctIndex,
      subject: String(raw.subject || "").trim(),
      lessonKey: resolveCustomChapterLessonKey({ lessonKey: raw.lessonKey || raw.lesson_key || "" }),
      explanation: String(raw.explanation || "").trim(),
    };
  }
  if (type === "truefalse") {
    return {
      id: String(raw.id || `question_${index}`).trim(),
      type,
      prompt,
      correct: Boolean(raw.correct),
      subject: String(raw.subject || "").trim(),
      lessonKey: resolveCustomChapterLessonKey({ lessonKey: raw.lessonKey || raw.lesson_key || "" }),
      explanation: String(raw.explanation || "").trim(),
    };
  }
  if (type === "fillblank") {
    const answer = String(raw.answer || raw.correctAnswer || "").trim();
    if (!answer) return null;
    return {
      id: String(raw.id || `question_${index}`).trim(),
      type,
      prompt,
      answer,
      subject: String(raw.subject || "").trim(),
      lessonKey: resolveCustomChapterLessonKey({ lessonKey: raw.lessonKey || raw.lesson_key || "" }),
      explanation: String(raw.explanation || "").trim(),
    };
  }
  const pairs = Array.isArray(raw.pairs)
    ? raw.pairs.map((pair, pairIndex) => ({
      left: String(pair?.left || pair?.prompt || "").trim(),
      right: String(pair?.right || pair?.answer || "").trim(),
      id: String(pair?.id || `pair_${pairIndex}`).trim(),
    })).filter((pair) => pair.left && pair.right)
    : [];
  if (!pairs.length) return null;
  return {
    id: String(raw.id || `question_${index}`).trim(),
    type,
    prompt: prompt || "Match the pairs",
    pairs,
    subject: String(raw.subject || "").trim(),
    lessonKey: resolveCustomChapterLessonKey({ lessonKey: raw.lessonKey || raw.lesson_key || "" }),
    explanation: String(raw.explanation || "").trim(),
  };
}

function normalizeLocalTestTemplateRecord(raw, index = 0) {
  if (!raw || typeof raw !== "object") return null;
  const templateId = String(raw.templateId || raw.template_id || raw.id || `local_test_${index}`).trim();
  if (!templateId) return null;
  const payload = raw.payload && typeof raw.payload === "object" ? raw.payload : raw;
  const questions = Array.isArray(payload.questions)
    ? payload.questions.map((question, questionIndex) => normalizeTestQuestionRecord(question, questionIndex)).filter(Boolean)
    : [];
  return {
    templateId,
    schoolId: String(raw.schoolId || raw.school_id || "").trim(),
    authorEmail: String(raw.authorEmail || raw.author_email || "").trim().toLowerCase(),
    title: String(payload.title || raw.title || "Saturday Test").trim(),
    grade: Number(payload.grade ?? raw.grade) || null,
    subjectScope: Array.isArray(payload.subjectScope || payload.subject_scope || raw.subjectScope || raw.subject_scope)
      ? (payload.subjectScope || payload.subject_scope || raw.subjectScope || raw.subject_scope).map((value) => String(value || "").trim()).filter(Boolean)
      : [],
    payload: {
      title: String(payload.title || raw.title || "Saturday Test").trim(),
      instructions: String(payload.instructions || raw.instructions || "").trim(),
      questions,
    },
    isPublished: Boolean(raw.isPublished || raw.is_published),
    publishedAt: Number(raw.publishedAt || raw.published_at || raw.updatedAt || raw.updated_at || Date.now()) || Date.now(),
    updatedAt: Number(raw.updatedAt || raw.updated_at || raw.createdAt || raw.created_at || Date.now()) || Date.now(),
    deletedAt: null,
    source: String(raw.source || "local").trim().toLowerCase() || "local",
  };
}

function normalizeLocalTestTemplateLibrary(raw) {
  return (Array.isArray(raw) ? raw : [])
    .map((entry, index) => normalizeLocalTestTemplateRecord(entry, index))
    .filter(Boolean)
    .sort((left, right) => (right.updatedAt || 0) - (left.updatedAt || 0));
}

function getInstitutionRoleRank(role) {
  const safeRole = String(role || "").trim().toLowerCase();
  if (safeRole === "admin") return 700;
  if (safeRole === "editor") return 650;
  if (safeRole === "school_owner") return 600;
  if (safeRole === "principal") return 500;
  if (safeRole === "teacher") return 400;
  if (safeRole === "parent") return 300;
  if (safeRole === "student") return 200;
  return 0;
}

function getHighestInstitutionRole(roles = []) {
  return (Array.isArray(roles) ? roles : [])
    .map((role) => String(role || "").trim().toLowerCase())
    .sort((left, right) => getInstitutionRoleRank(right) - getInstitutionRoleRank(left))[0] || "";
}

function normalizeGradeScopeArray(raw) {
  if (Array.isArray(raw)) {
    return raw
      .map((value) => Number(value))
      .filter((value) => Number.isFinite(value) && value >= 1 && value <= 12)
      .filter((value, index, list) => list.indexOf(value) === index)
      .sort((left, right) => left - right);
  }
  const text = String(raw || "").trim();
  if (!text) return [];
  return text
    .split(/[,\s]+/)
    .map((value) => Number(value))
    .filter((value) => Number.isFinite(value) && value >= 1 && value <= 12)
    .filter((value, index, list) => list.indexOf(value) === index)
    .sort((left, right) => left - right);
}

function buildDiaryTaskKey(kind, payload = {}) {
  const safeKind = String(kind || "auto").trim().toLowerCase();
  if (safeKind === "assigned") return `assigned::${String(payload.diaryId || payload.diary_id || "").trim()}`;
  if (safeKind === "assignment") return `assignment::${String(payload.diaryId || payload.diary_id || "").trim()}`;
  if (safeKind === "test") return `test::${String(payload.templateId || payload.template_id || "").trim()}::${String(payload.weekStartDate || payload.week_start_date || "").trim()}`;
  return [
    "auto",
    String(payload.subject || "").trim(),
    resolveCustomChapterLessonKey({ lessonKey: payload.lessonKey || payload.lesson_key || "" }),
    String(payload.dayIndex ?? payload.day_index ?? ""),
    String(payload.unitKey || payload.unit_key || "").trim(),
  ].join("::");
}

function getDiaryTaskRouteKey(task) {
  if (!task || typeof task !== "object") return "";
  return `${String(task.taskKind || "").trim().toLowerCase()}::${String(task.taskKey || "").trim()}`;
}

function isLessonProgressComplete(lesson, completedQuizzes = {}, practiceLessonProgress = {}, autoDiarySettings = null) {
  if (!lesson) return false;
  const settings = normalizeAutoDiarySettings(autoDiarySettings || {});
  const lessonId = String(lesson.id || "").trim();
  const lessonKey = String(getLessonKeyValue(lesson) || lesson.key || "").trim();
  const checks = [];
  if (settings.progression.countQuizComplete && lessonId) {
    checks.push(Boolean(completedQuizzes?.[lessonId]));
  }
  if (lessonKey) {
    const progress = practiceLessonProgress?.[lessonKey];
    if (settings.progression.countLessonProgress) {
      checks.push(Boolean(progress?.completed) || Number(progress?.percentComplete) >= Number(settings.progression.lessonProgressThreshold || 100));
    }
  }
  if (!checks.length) {
    if (lessonId && completedQuizzes?.[lessonId]) return true;
    if (lessonKey) {
      const progress = practiceLessonProgress?.[lessonKey];
      if (progress?.completed) return true;
      if (Number(progress?.percentComplete) >= 100) return true;
    }
    return false;
  }
  return settings.progression.completionMode === "all"
    ? checks.every(Boolean)
    : checks.some(Boolean);
}

function buildAutoDiaryWeekPlan({
  subjects = [],
  grade = null,
  weekDates = [],
  yearStartDate = "",
  autoDiarySettings = null,
  schoolId = "",
  getLessonGroups,
  getQuiz,
  completedQuizzes = {},
  practiceLessonProgress = {},
  diaryCompletions = [],
  studentEmail = "",
}) {
  if (!Number.isFinite(Number(grade)) || !Array.isArray(weekDates) || weekDates.length < 7 || typeof getLessonGroups !== "function" || typeof getQuiz !== "function") {
    return [];
  }
  const settings = normalizeAutoDiarySettings(autoDiarySettings || {}, { yearStartDate });
  const studyDates = getConfiguredStudyDates(weekDates, settings);
  const academicWeekNumber = getAcademicWeekNumber(studyDates[0] || weekDates[0] || Date.now(), yearStartDate);
  const safeStudyDays = studyDates.length || settings.calendar.studyDays.length || 5;
  const safeSubjects = orderAutoDiarySubjects(
    (Array.isArray(subjects) ? subjects : []).filter((subject) => shouldIncludeAutoDiarySubject(subject, settings)),
    settings,
  );
  const safeAutoDiaryStartDate = String(settings.calendar.startDate || "").trim();
  const lessonCoverageLookup = buildAutoDiaryLessonCoverageLookup({
    diaryCompletions,
    studentEmail,
    schoolId,
    currentWeekStartDate: studyDates[0] || weekDates[0] || "",
    studyDays: safeStudyDays,
  });
  const dailySubjectPlanLookup = buildAutoDiaryDailySubjectPlanLookup(safeSubjects, studyDates, settings);
  return safeSubjects.flatMap((subject, subjectIndex) => {
    try {
      const lessonGroups = (getLessonGroups(subject.id, grade) || []).filter((group) => group?.activeLesson);
      if (!lessonGroups.length) return [];
      const lessonPlans = lessonGroups.map((group) => {
        const lesson = group?.activeLesson;
        const canonicalLessonKey = resolveCustomChapterLessonKey({ lessonKey: group?.canonicalLessonKey || lesson?.key || lesson?.id || "" });
        const quizRows = getQuiz(subject.id, grade, canonicalLessonKey);
        const units = extractLessonWorkUnits(lesson, Array.isArray(quizRows) ? quizRows : []);
        return {
          chapterGroup: group,
          lesson,
          canonicalLessonKey,
          units,
          buckets: distributeWorkUnitsAcrossStudyDays(units, safeStudyDays, {
            minimumUnitsPerDay: settings.progression.minimumUnitsPerDay,
            reviewWhenShort: settings.progression.reviewWhenShort,
          }),
          completedSlots: getAutoDiaryLessonCoverageSlots({
            subjectId: subject.id,
            chapterGroup: group,
            completedQuizzes,
            practiceLessonProgress,
            lessonCoverageLookup,
            studyDays: safeStudyDays,
            autoDiarySettings: settings,
          }),
        };
      }).filter((entry) => entry.lesson && entry.canonicalLessonKey);
      if (!lessonPlans.length) return [];
      const carryForwardEnabled = settings.progression.advanceMode !== "weekly_lesson";
      const weeklyLessonIndex = (() => {
        if (settings.progression.chapterSelectionMode === "curriculum_order") {
          return Math.min(lessonPlans.length - 1, Math.max(0, academicWeekNumber - 1));
        }
        const unfinishedIndex = lessonPlans.findIndex((entry) => (
          settings.progression.skipCompletedLessons
            ? entry.completedSlots < safeStudyDays
            : true
        ));
        return unfinishedIndex >= 0 ? unfinishedIndex : Math.min(lessonPlans.length - 1, Math.max(0, academicWeekNumber - 1));
      })();
      let currentLessonIndex = carryForwardEnabled
        ? lessonPlans.findIndex((entry) => (
          settings.progression.skipCompletedLessons
            ? entry.completedSlots < safeStudyDays
            : true
        ))
        : weeklyLessonIndex;
      if (currentLessonIndex < 0) currentLessonIndex = lessonPlans.length - 1;
      let currentSlotIndex = carryForwardEnabled ? Math.min(lessonPlans[currentLessonIndex]?.completedSlots || 0, safeStudyDays - 1) : 0;
      const allLessonsCompleted = carryForwardEnabled && lessonPlans.every((entry) => entry.completedSlots >= safeStudyDays);
      return studyDates.flatMap((targetDate, dayIndex) => {
        if (safeAutoDiaryStartDate && targetDate < safeAutoDiaryStartDate) return [];
        if (!Array.isArray(dailySubjectPlanLookup[targetDate]) || !dailySubjectPlanLookup[targetDate].includes(subject.id)) {
          return [];
        }
        let selectedPlan = null;
        let bucketIndex = 0;
        if (!carryForwardEnabled) {
          selectedPlan = lessonPlans[weeklyLessonIndex] || lessonPlans[0];
          bucketIndex = dayIndex % safeStudyDays;
        } else if (allLessonsCompleted) {
          selectedPlan = lessonPlans[lessonPlans.length - 1] || lessonPlans[0];
          bucketIndex = dayIndex % safeStudyDays;
        } else {
          while (currentLessonIndex < lessonPlans.length && (lessonPlans[currentLessonIndex]?.completedSlots || 0) >= safeStudyDays) {
            currentLessonIndex += 1;
            currentSlotIndex = Math.min(lessonPlans[currentLessonIndex]?.completedSlots || 0, safeStudyDays - 1);
          }
          selectedPlan = lessonPlans[currentLessonIndex] || lessonPlans[lessonPlans.length - 1] || lessonPlans[0];
          bucketIndex = Math.min(currentSlotIndex, safeStudyDays - 1);
        }
        const selectedGroup = selectedPlan?.chapterGroup || null;
        const lesson = selectedPlan?.lesson || null;
        if (!selectedGroup || !lesson) return [];
        const bucketUnits = Array.isArray(selectedPlan?.buckets?.[bucketIndex]) ? selectedPlan.buckets[bucketIndex] : [];
        const fallbackUnit = {
          key: `${subject.id}_${selectedGroup.canonicalLessonKey}_overview_${dayIndex + 1}`,
          title: lesson.title || `${subject.name || subject.id} lesson`,
          detail: joinLocalizedText("Study the lesson and complete its practice.", "سبق پڑھیں اور اس کی مشق مکمل کریں۔", "en"),
          kind: "overview",
        };
        const leadUnit = bucketUnits[0] || fallbackUnit;
        const derivedTaskTitle = String(leadUnit?.sourceMeta?.title || leadUnit?.title || lesson.title || `${subject.name || subject.id} lesson`).trim()
          || String(lesson.title || `${subject.name || subject.id} lesson`).trim();
        const subsectionTitle = getAutoDiaryUnitSubsectionTitle(leadUnit, lesson.title || `${subject.name || subject.id} lesson`);
        const subsectionKey = getAutoDiaryUnitSubsectionKey(leadUnit, bucketIndex, subsectionTitle);
        const task = {
          taskKind: "auto",
          taskKey: buildDiaryTaskKey("auto", {
            subject: subject.id,
            lessonKey: selectedGroup.canonicalLessonKey,
            dayIndex: dayIndex + 1,
            unitKey: bucketUnits[0]?.key || fallbackUnit.key,
          }),
          schoolId: schoolId || "",
          targetDate,
          weekStartDate: weekDates[0],
          dayIndex: dayIndex + 1,
          academicWeekNumber,
          subject: subject.id,
          subjectLabel: subject.name || subject.id,
          subjectLabelUr: subject.nameUr || subject.name || subject.id,
          lessonKey: selectedGroup.canonicalLessonKey,
          contentId: String(selectedGroup.activeVariant?.contentId || "").trim(),
          title: derivedTaskTitle,
          subsectionKey,
          subsectionTitle,
          note: "",
          source: "auto",
          taskUnits: bucketUnits.length ? bucketUnits : [fallbackUnit],
          chapterGroup: selectedGroup,
          lesson,
          subjectIndex,
        };
        if (carryForwardEnabled && !allLessonsCompleted) {
          currentSlotIndex += 1;
          if (currentSlotIndex >= safeStudyDays) {
            currentLessonIndex += 1;
            currentSlotIndex = Math.min(lessonPlans[currentLessonIndex]?.completedSlots || 0, safeStudyDays - 1);
          }
        }
        return [task];
      });
    } catch (error) {
      console.log("Unable to build auto diary task for subject:", subject?.id, error);
      return [];
    }
  });
}

function getAutoDiaryOverrideSpecificity(entry, studentEmail = "") {
  const safeStudentEmail = String(studentEmail || "").trim().toLowerCase();
  if (String(entry?.targetType || "").trim().toLowerCase() === "student" && safeStudentEmail && String(entry?.targetStudentEmail || "").trim().toLowerCase() === safeStudentEmail) {
    return 2;
  }
  return 1;
}

function compareAutoDiaryOverrides(left, right, studentEmail = "") {
  const specificityDelta = getAutoDiaryOverrideSpecificity(right, studentEmail) - getAutoDiaryOverrideSpecificity(left, studentEmail);
  if (specificityDelta) return specificityDelta;
  const updatedDelta = Number(right?.updatedAt || 0) - Number(left?.updatedAt || 0);
  if (updatedDelta) return updatedDelta;
  return Number(right?.createdAt || 0) - Number(left?.createdAt || 0);
}

function buildAutoDiaryOverrideTask({
  overrideRecord,
  baseTask,
  subjects = [],
  grade = null,
  getLessonGroups,
  getQuiz,
  yearStartDate = "",
}) {
  try {
    const override = normalizeAutoDiaryOverrideRecord(overrideRecord);
    if (!override || !baseTask || !Number.isFinite(Number(grade)) || typeof getLessonGroups !== "function" || typeof getQuiz !== "function") return null;
    const subjectId = String(override.overrideSubject || baseTask.subject || "").trim();
    const lessonKey = resolveCustomChapterLessonKey({ lessonKey: override.overrideLessonKey || baseTask.lessonKey || "" });
    if (!subjectId || !lessonKey) return null;
    const lessonGroups = (getLessonGroups(subjectId, grade) || []).filter((group) => group?.activeLesson);
    const chapterGroup = lessonGroups.find((group) => group?.canonicalLessonKey === lessonKey) || null;
    if (!chapterGroup) return null;
    const desiredContentId = String(override.overrideContentId || "").trim();
    const matchedVariant = desiredContentId
      ? (chapterGroup.variants || []).find((variant) => String(variant?.contentId || "").trim() === desiredContentId)
      : null;
    const lesson = matchedVariant?.lesson || chapterGroup.activeLesson || null;
    if (!lesson) return null;
    const quizRows = getQuiz(subjectId, grade, lessonKey);
    const units = extractLessonWorkUnits(lesson, Array.isArray(quizRows) ? quizRows : []);
    const fallbackUnit = {
      key: `${subjectId}_${lessonKey}_override_overview`,
      title: String(lesson.title || baseTask.title || "").trim() || `${subjectId} lesson`,
      detail: joinLocalizedText("Study the selected lesson content.", "منتخب سبق کے مواد کا مطالعہ کریں۔", "en"),
      kind: "overview",
    };
    const subsectionGroups = groupAutoDiaryUnitsBySubsection(units, lesson.title || baseTask.title || `${subjectId} lesson`);
    const selectedSubsectionKey = String(override.overrideSubsectionKey || "").trim();
    const selectedSubsection = subsectionGroups.find((group) => group.key === selectedSubsectionKey)
      || subsectionGroups.find((group) => group.title === String(override.overrideSubsectionTitle || "").trim())
      || subsectionGroups[0]
      || null;
    const candidateUnits = selectedSubsection?.units?.length ? selectedSubsection.units : units;
    const preferredUnitKeys = new Set(
      (Array.isArray(override.overrideUnitKeys) && override.overrideUnitKeys.length
        ? override.overrideUnitKeys
        : [String(override.overrideUnitKey || "").trim()]
      ).filter(Boolean),
    );
    const selectedUnits = candidateUnits.filter((unit) => preferredUnitKeys.has(String(unit?.key || "").trim()));
    const resolvedUnits = selectedUnits.length
      ? selectedUnits
      : candidateUnits.length
        ? candidateUnits
        : [units[0] || fallbackUnit];
    const leadUnit = resolvedUnits[0] || units[0] || fallbackUnit;
    const subjectEntry = (Array.isArray(subjects) ? subjects : []).find((subject) => String(subject?.id || "").trim() === subjectId) || null;
    const subsectionTitle = String(
      override.overrideSubsectionTitle
      || selectedSubsection?.title
      || getAutoDiaryUnitSubsectionTitle(leadUnit, lesson.title || baseTask.title || `${subjectId} lesson`)
      || "",
    ).trim();
    const title = String(subsectionTitle || leadUnit?.sourceMeta?.title || leadUnit?.title || lesson.title || baseTask.title || "").trim()
      || String(lesson.title || baseTask.title || `${subjectId} lesson`).trim();
    return {
      ...baseTask,
      taskKind: "auto",
      taskKey: `override::${override.overrideId}`,
      baseTaskKey: String(baseTask.baseTaskKey || baseTask.taskKey || "").trim() || String(baseTask.taskKey || "").trim(),
      overrideId: override.overrideId,
      overrideAction: override.action,
      overrideRecord: override,
      source: override.action === "add" ? "auto_added" : "auto_override",
      subject: subjectId,
      subjectLabel: subjectEntry?.name || subjectId,
      subjectLabelUr: subjectEntry?.nameUr || subjectEntry?.name || subjectId,
      lessonKey,
      contentId: desiredContentId || String(chapterGroup.activeVariant?.contentId || "").trim(),
      title,
      subsectionKey: selectedSubsection?.key || getAutoDiaryUnitSubsectionKey(leadUnit, 0, subsectionTitle),
      subsectionTitle,
      note: String(override.note || baseTask.note || "").trim(),
      taskUnits: resolvedUnits,
      chapterGroup,
      lesson,
      academicWeekNumber: getAcademicWeekNumber(baseTask.targetDate || override.targetDate, yearStartDate),
      subjectIndex: Number.isFinite(baseTask?.subjectIndex) ? baseTask.subjectIndex : Math.max(0, (Array.isArray(subjects) ? subjects : []).findIndex((subject) => String(subject?.id || "").trim() === subjectId)),
      displayOrder: Number(baseTask?.displayOrder || 0) + (override.action === "add" ? 0.1 + (Math.max(0, Number(override.displayOrder) || 0) / 1000) : 0),
    };
  } catch (error) {
    console.log("Unable to build auto diary override task:", error);
    return null;
  }
}

function applyAutoDiaryOverrides({
  autoTasks = [],
  overrides = [],
  schoolId = "",
  weekStartDate = "",
  grade = null,
  studentEmail = "",
  subjects = [],
  getLessonGroups,
  getQuiz,
  yearStartDate = "",
  includeSkippedTasks = false,
}) {
  const safeTasks = Array.isArray(autoTasks) ? autoTasks.filter(Boolean) : [];
  const safeSchoolId = String(schoolId || "").trim();
  const safeWeekStartDate = String(weekStartDate || "").trim();
  const safeStudentEmail = String(studentEmail || "").trim().toLowerCase();
  const safeOverrides = (Array.isArray(overrides) ? overrides : [])
    .map((entry) => normalizeAutoDiaryOverrideRecord(entry))
    .filter(Boolean)
    .filter((entry) => entry.status === "active")
    .filter((entry) => !safeSchoolId || entry.schoolId === safeSchoolId)
    .filter((entry) => !safeWeekStartDate || entry.weekStartDate === safeWeekStartDate)
    .filter((entry) => String(entry.targetType || "").trim().toLowerCase() === "student"
      ? (safeStudentEmail && entry.targetStudentEmail === safeStudentEmail)
      : Number(entry.targetGrade) === Number(grade));
  if (!safeOverrides.length) return safeTasks;
  const overridesByAnchor = new Map();
  safeOverrides.forEach((entry) => {
    const key = `${entry.targetDate}::${entry.baseTaskKey}`;
    if (!overridesByAnchor.has(key)) overridesByAnchor.set(key, []);
    overridesByAnchor.get(key).push(entry);
  });
  const resolvedTasks = [];
  safeTasks.forEach((task) => {
    const baseTaskKey = String(task?.baseTaskKey || task?.taskKey || "").trim();
    const anchorKey = `${String(task?.targetDate || "").trim()}::${baseTaskKey}`;
    const anchoredOverrides = overridesByAnchor.get(anchorKey) || [];
    const directOverride = anchoredOverrides
      .filter((entry) => entry.action !== "add")
      .sort((left, right) => compareAutoDiaryOverrides(left, right, safeStudentEmail))[0] || null;
    const addOverrides = anchoredOverrides
      .filter((entry) => entry.action === "add")
      .sort((left, right) => compareAutoDiaryOverrides(left, right, safeStudentEmail) || (Number(left.displayOrder || 0) - Number(right.displayOrder || 0)));
    let renderedBaseTask = task;
    if (directOverride?.action === "skip") {
      if (includeSkippedTasks) {
        renderedBaseTask = {
          ...task,
          baseTaskKey,
          overrideId: directOverride.overrideId,
          overrideAction: "skip",
          overrideRecord: directOverride,
          source: "auto_skipped",
          isSkipped: true,
        };
        resolvedTasks.push(renderedBaseTask);
      }
    } else {
      if (directOverride?.action === "replace") {
        renderedBaseTask = buildAutoDiaryOverrideTask({
          overrideRecord: directOverride,
          baseTask: { ...task, baseTaskKey },
          subjects,
          grade,
          getLessonGroups,
          getQuiz,
          yearStartDate,
        }) || task;
      } else {
        renderedBaseTask = { ...task, baseTaskKey };
      }
      resolvedTasks.push(renderedBaseTask);
      addOverrides.forEach((entry) => {
        const addedTask = buildAutoDiaryOverrideTask({
          overrideRecord: entry,
          baseTask: { ...task, baseTaskKey },
          subjects,
          grade,
          getLessonGroups,
          getQuiz,
          yearStartDate,
        });
        if (addedTask) resolvedTasks.push(addedTask);
      });
    }
  });
  return resolvedTasks.sort((left, right) => {
    if (String(left.targetDate || "").localeCompare(String(right.targetDate || "")) !== 0) {
      return String(left.targetDate || "").localeCompare(String(right.targetDate || ""));
    }
    if (Number(left.dayIndex || 0) !== Number(right.dayIndex || 0)) return Number(left.dayIndex || 0) - Number(right.dayIndex || 0);
    if (Number(left.subjectIndex || 0) !== Number(right.subjectIndex || 0)) return Number(left.subjectIndex || 0) - Number(right.subjectIndex || 0);
    if (Number(left.displayOrder || 0) !== Number(right.displayOrder || 0)) return Number(left.displayOrder || 0) - Number(right.displayOrder || 0);
    return String(left.subject || "").localeCompare(String(right.subject || ""));
  });
}

function buildLegacyPriorWeeksCoveredTasks({
  currentWeekStartDate = "",
  accumulationMode = "rolling",
  accumulationValue = 8,
  yearStartDate = "",
  subjects = [],
  grade = null,
  getLessonGroups,
  currentWeekLessonKeys = null,
}) {
  const anchor = parseIsoDateValue(currentWeekStartDate);
  if (!anchor || !Number.isFinite(Number(grade)) || typeof getLessonGroups !== "function") return [];
  const mode = String(accumulationMode || "rolling").trim().toLowerCase();
  const rollingMax = Math.max(1, Math.min(52, Number(accumulationValue) || 8));
  const currentAcademicWeek = getAcademicWeekNumber(anchor, yearStartDate);
  const priorWeeksAvailable = Math.max(0, currentAcademicWeek - 1);
  const weekCount = (mode === "academic_year" || mode === "since_start")
    ? Math.min(52, priorWeeksAvailable)
    : Math.min(rollingMax, priorWeeksAvailable);
  if (weekCount <= 0) return [];
  const safeCurrentKeys = currentWeekLessonKeys instanceof Set ? currentWeekLessonKeys : new Set();
  const priorTasks = [];
  const seen = new Set();
  (Array.isArray(subjects) ? subjects : []).forEach((subject, subjectIndex) => {
    if (!subject || !subject.id) return;
    try {
      const lessonGroups = (getLessonGroups(subject.id, grade) || []).filter((group) => group?.activeLesson);
      if (!lessonGroups.length) return;
      for (let offset = 1; offset <= weekCount; offset += 1) {
        const priorAcademicWeek = currentAcademicWeek - offset;
        if (priorAcademicWeek < 1) break;
        const groupIndex = Math.min(lessonGroups.length - 1, Math.max(0, priorAcademicWeek - 1));
        const group = lessonGroups[groupIndex];
        const lesson = group?.activeLesson;
        if (!lesson || !group?.canonicalLessonKey) continue;
        const lessonKey = `${subject.id}::${group.canonicalLessonKey}`;
        if (seen.has(lessonKey) || safeCurrentKeys.has(lessonKey)) continue;
        seen.add(lessonKey);
        priorTasks.push({
          taskKind: "auto",
          taskKey: `prior::${subject.id}::${group.canonicalLessonKey}::wk${priorAcademicWeek}`,
          subject: subject.id,
          subjectLabel: subject.name || subject.id,
          subjectLabelUr: subject.nameUr || subject.name || subject.id,
          lessonKey: group.canonicalLessonKey,
          contentId: String(group.activeVariant?.contentId || "").trim(),
          title: lesson.title || `${subject.name || subject.id} lesson`,
          note: "",
          source: "prior_auto",
          taskUnits: [],
          chapterGroup: group,
          lesson,
          subjectIndex,
          priorAcademicWeek,
        });
      }
    } catch (error) {
      console.log("Unable to build prior-week coverage for subject:", subject?.id, error);
    }
  });
  return priorTasks;
}

function resolveDiaryCoverageRangeStartDate({
  currentWeekStartDate = "",
  accumulationMode = "rolling",
  accumulationValue = 8,
  yearStartDate = "",
  historyRows = [],
}) {
  const currentWeekStart = parseIsoDateValue(currentWeekStartDate);
  if (!currentWeekStart) return "";
  const mode = String(accumulationMode || "rolling").trim().toLowerCase();
  if (mode === "rolling") {
    const rollingWeeks = Math.max(1, Math.min(52, Number(accumulationValue) || 8));
    const rangeStart = new Date(currentWeekStart.getTime());
    rangeStart.setDate(rangeStart.getDate() - (rollingWeeks * 7));
    return toIsoDateString(rangeStart);
  }
  if (mode === "academic_year") {
    const yearStart = getWeekStartDate(yearStartDate || new Date(currentWeekStart.getFullYear(), 0, 1));
    return toIsoDateString(yearStart || currentWeekStart);
  }
  const historyDates = (Array.isArray(historyRows) ? historyRows : [])
    .map((row) => String(row?.targetDate || "").trim())
    .filter(Boolean)
    .sort();
  if (historyDates.length) return historyDates[0];
  return toIsoDateString(getWeekStartDate(yearStartDate || new Date(currentWeekStart.getFullYear(), 0, 1)) || currentWeekStart);
}

function buildHydratedHistoricalDiaryTask({
  historyRecord,
  subjects = [],
  grade = null,
  getLessonGroups,
  getQuiz,
  yearStartDate = "",
}) {
  try {
    if (!historyRecord || typeof getLessonGroups !== "function" || typeof getQuiz !== "function") return null;
    const safeSubject = String(historyRecord.subject || "").trim();
    const safeLessonKey = resolveCustomChapterLessonKey({ lessonKey: historyRecord.lessonKey || "" });
    if (!safeSubject || !safeLessonKey || !Number.isFinite(Number(grade))) return null;
    const lessonGroups = (getLessonGroups(safeSubject, grade) || []).filter((group) => group?.activeLesson);
    const chapterGroup = lessonGroups.find((group) => group?.canonicalLessonKey === safeLessonKey) || null;
    if (!chapterGroup) return null;
    const desiredContentId = String(historyRecord.contentId || "").trim();
    const matchedVariant = desiredContentId
      ? (chapterGroup.variants || []).find((variant) => String(variant?.contentId || "").trim() === desiredContentId)
      : null;
    const lesson = matchedVariant?.lesson || chapterGroup.activeLesson || null;
    if (!lesson) return null;
    const quizRows = getQuiz(safeSubject, grade, safeLessonKey);
    const taskUnits = extractLessonWorkUnits(lesson, Array.isArray(quizRows) ? quizRows : []);
    const subjectIndex = Math.max(0, (Array.isArray(subjects) ? subjects : []).findIndex((subject) => subject?.id === safeSubject));
    const subjectEntry = (Array.isArray(subjects) ? subjects : []).find((subject) => subject?.id === safeSubject) || null;
    const coveredAtDate = parseIsoDateValue(historyRecord.targetDate || "") || new Date(historyRecord.coveredAt || Date.now());
    return {
      taskKind: "auto",
      taskKey: `history::${safeSubject}::${safeLessonKey}::${String(historyRecord.contentId || "builtin").trim() || "builtin"}::${toIsoDateString(coveredAtDate)}`,
      schoolId: String(historyRecord.schoolId || "").trim(),
      targetDate: toIsoDateString(coveredAtDate),
      weekStartDate: toIsoDateString(getWeekStartDate(coveredAtDate)),
      dayIndex: Math.max(1, Math.min(7, Number(historyRecord.dayIndex) || 1)),
      academicWeekNumber: getAcademicWeekNumber(coveredAtDate, yearStartDate),
      subject: safeSubject,
      subjectLabel: subjectEntry?.name || safeSubject,
      subjectLabelUr: subjectEntry?.nameUr || subjectEntry?.name || safeSubject,
      lessonKey: safeLessonKey,
      contentId: desiredContentId || String(chapterGroup.activeVariant?.contentId || "").trim(),
      title: lesson.title || chapterGroup.activeLesson?.title || `${subjectEntry?.name || safeSubject} lesson`,
      note: String(historyRecord.note || "").trim(),
      source: historyRecord.source || "history",
      taskUnits,
      chapterGroup,
      lesson,
      subjectIndex,
      coveredAt: Number(coveredAtDate.getTime()) || Date.now(),
      coverageEvidence: String(historyRecord.coverageEvidence || "").trim() || "history",
    };
  } catch (error) {
    console.log("Unable to hydrate historical diary task:", historyRecord?.subject, historyRecord?.lessonKey, error);
    return null;
  }
}

function buildPriorWeeksCoveredTasks({
  currentWeekStartDate = "",
  accumulationMode = "rolling",
  accumulationValue = 8,
  yearStartDate = "",
  subjects = [],
  grade = null,
  getLessonGroups,
  getQuiz,
  currentWeekLessonKeys = null,
  diaryEntries = [],
  diaryCompletions = [],
  studentEmail = "",
}) {
  try {
    const safeStudentEmail = String(studentEmail || "").trim().toLowerCase();
    const safeCurrentKeys = currentWeekLessonKeys instanceof Set ? currentWeekLessonKeys : new Set();
    const normalizedCompletions = (Array.isArray(diaryCompletions) ? diaryCompletions : [])
      .map((entry) => normalizeDiaryCompletionRecord(entry))
      .filter(Boolean)
      .filter((entry) => entry.studentEmail === safeStudentEmail && entry.subject && entry.lessonKey && entry.targetDate && entry.targetDate < currentWeekStartDate);
    const normalizedEntries = (Array.isArray(diaryEntries) ? diaryEntries : [])
      .map((entry) => normalizeDiaryEntryRecord(entry))
      .filter(Boolean)
      .filter((entry) => entry.entryType !== "assignment" && entry.subject && entry.lessonKey && entry.targetDate && entry.targetDate < currentWeekStartDate)
      .filter((entry) => {
        if (entry.targetType === "student") return entry.targetStudentEmail === safeStudentEmail;
        return Number(entry.targetGrade) === Number(grade);
      });
    const historyRows = [
      ...normalizedCompletions.map((entry) => ({
        schoolId: entry.schoolId,
        subject: entry.subject,
        lessonKey: entry.lessonKey,
        contentId: entry.contentId,
        note: entry.completionPayload?.note || "",
        targetDate: entry.targetDate,
        coveredAt: Number(entry.completedAt || entry.updatedAt || Date.parse(entry.targetDate) || Date.now()),
        coverageEvidence: "completion",
        source: entry.completionPayload?.source || "history_completed",
      })),
      ...normalizedEntries.map((entry) => ({
        schoolId: entry.schoolId,
        subject: entry.subject,
        lessonKey: entry.lessonKey,
        contentId: entry.contentId,
        note: entry.note,
        targetDate: entry.targetDate,
        coveredAt: Number(entry.updatedAt || Date.parse(entry.targetDate) || Date.now()),
        coverageEvidence: "assigned",
        source: "history_assigned",
      })),
    ];
    const rangeStartDate = resolveDiaryCoverageRangeStartDate({
      currentWeekStartDate,
      accumulationMode,
      accumulationValue,
      yearStartDate,
      historyRows,
    });
    const filteredHistoryRows = historyRows.filter((entry) => entry.targetDate >= rangeStartDate && entry.targetDate < currentWeekStartDate);
    const historyByLesson = new Map();
    filteredHistoryRows.forEach((entry) => {
      const key = [
        String(entry.subject || "").trim(),
        resolveCustomChapterLessonKey({ lessonKey: entry.lessonKey || "" }),
        String(entry.contentId || "").trim() || "__default__",
      ].join("::");
      const currentLessonKey = `${String(entry.subject || "").trim()}::${resolveCustomChapterLessonKey({ lessonKey: entry.lessonKey || "" })}`;
      if (!key || safeCurrentKeys.has(currentLessonKey)) return;
      const existing = historyByLesson.get(key);
      const existingRank = existing?.coverageEvidence === "completion" ? 2 : existing?.coverageEvidence === "assigned" ? 1 : 0;
      const nextRank = entry.coverageEvidence === "completion" ? 2 : entry.coverageEvidence === "assigned" ? 1 : 0;
      if (!existing || nextRank > existingRank || (nextRank === existingRank && Number(entry.coveredAt || 0) > Number(existing.coveredAt || 0))) {
        historyByLesson.set(key, entry);
      }
    });
    const hydratedHistory = Array.from(historyByLesson.values())
      .sort((left, right) => Number(right.coveredAt || 0) - Number(left.coveredAt || 0))
      .map((entry) => buildHydratedHistoricalDiaryTask({
        historyRecord: entry,
        subjects,
        grade,
        getLessonGroups,
        getQuiz,
        yearStartDate,
      }))
      .filter(Boolean);
    if (hydratedHistory.length) return hydratedHistory;
  } catch (error) {
    console.log("Unable to build prior-week covered tasks:", error);
  }
  return buildLegacyPriorWeeksCoveredTasks({
    currentWeekStartDate,
    accumulationMode,
    accumulationValue,
    yearStartDate,
    subjects,
    grade,
    getLessonGroups,
    currentWeekLessonKeys,
  });
}

function buildDiaryTasksForWeek({
  autoTasks = [],
  diaryEntries = [],
  subjectsById = {},
  chapterGroupLookup = {},
  yearStartDate = "",
}) {
  const normalizedEntries = Array.isArray(diaryEntries) ? diaryEntries : [];
  const assignedTasks = normalizedEntries
    .filter((entry) => String(entry?.entryType || "").trim().toLowerCase() !== "assignment")
    .map((entry) => {
    const parsedTargetDate = parseIsoDateValue(entry.targetDate || "");
    if (!parsedTargetDate) return null;
    const subject = subjectsById?.[entry.subject] || null;
    const chapterGroup = chapterGroupLookup?.[`${entry.subject}::${Number(entry.targetGrade || 0)}::${entry.lessonKey}`] || null;
    const lesson = chapterGroup?.activeLesson || null;
    return {
      taskKind: "assigned",
      taskKey: buildDiaryTaskKey("assigned", entry),
      diaryId: entry.diaryId,
      schoolId: entry.schoolId,
      targetDate: entry.targetDate,
      weekStartDate: toIsoDateString(getWeekStartDate(parsedTargetDate)),
      dayIndex: Math.max(1, Math.min(7, Math.round((parsedTargetDate.getDay() + 6) % 7) + 1)),
      academicWeekNumber: getAcademicWeekNumber(entry.targetDate, yearStartDate),
      subject: entry.subject,
      subjectLabel: subject?.name || entry.subject,
      subjectLabelUr: subject?.nameUr || subject?.name || entry.subject,
      lessonKey: entry.lessonKey,
      contentId: entry.contentId,
      title: lesson?.title || joinLocalizedText("Assigned work", "تفویض شدہ کام", "en"),
      note: entry.note || "",
      source: "assigned",
      taskUnits: [],
      chapterGroup,
      lesson,
      rawEntry: entry,
    };
  })
    .filter(Boolean);
  const assignmentTasks = normalizedEntries
    .filter((entry) => String(entry?.entryType || "").trim().toLowerCase() === "assignment")
    .map((entry) => {
      const parsedTargetDate = parseIsoDateValue(entry.targetDate || "");
      if (!parsedTargetDate) return null;
      const linkedSubjectId = String(entry.subject || "").trim();
      const hasLinkedLesson = linkedSubjectId && linkedSubjectId !== "__assignment__" && String(entry.lessonKey || "").trim();
      const subject = hasLinkedLesson ? (subjectsById?.[linkedSubjectId] || null) : null;
      const chapterGroup = hasLinkedLesson
        ? chapterGroupLookup?.[`${linkedSubjectId}::${Number(entry.targetGrade || 0)}::${entry.lessonKey}`] || null
        : null;
      const lesson = chapterGroup?.activeLesson || null;
      const fallbackTitle = String(entry.assignmentTitle || "").trim() || joinLocalizedText("Assignment", "تفویض", "en");
      return {
        taskKind: "assignment",
        taskKey: buildDiaryTaskKey("assignment", entry),
        diaryId: entry.diaryId,
        schoolId: entry.schoolId,
        targetDate: entry.targetDate,
        weekStartDate: toIsoDateString(getWeekStartDate(parsedTargetDate)),
        dayIndex: Math.max(1, Math.min(7, Math.round((parsedTargetDate.getDay() + 6) % 7) + 1)),
        academicWeekNumber: getAcademicWeekNumber(entry.targetDate, yearStartDate),
        subject: hasLinkedLesson ? linkedSubjectId : "__assignment__",
        subjectLabel: hasLinkedLesson ? (subject?.name || linkedSubjectId) : joinLocalizedText("Assignments & Projects", "تفویضات اور پروجیکٹس", "en"),
        subjectLabelUr: hasLinkedLesson ? (subject?.nameUr || subject?.name || linkedSubjectId) : "تفویضات اور پروجیکٹس",
        lessonKey: hasLinkedLesson ? String(entry.lessonKey || "").trim() : "",
        contentId: hasLinkedLesson ? String(entry.contentId || "").trim() : "",
        title: fallbackTitle,
        note: String(entry.note || "").trim(),
        source: "assignment",
        taskUnits: String(entry.note || "").trim()
          ? [{
            key: `${String(entry.diaryId || "").trim()}_assignment_detail`,
            title: fallbackTitle,
            detail: String(entry.note || "").trim(),
            kind: "assignment",
            sourceMeta: null,
          }]
          : [],
        chapterGroup,
        lesson,
        rawEntry: entry,
      };
    })
    .filter(Boolean);
  const sourceOrder = {
    auto: 0,
    assigned: 1,
    assignment: 2,
  };
  return [...(Array.isArray(autoTasks) ? autoTasks : []), ...assignedTasks, ...assignmentTasks]
    .sort((left, right) => {
      if (String(left.targetDate || "").localeCompare(String(right.targetDate || "")) !== 0) {
        return String(left.targetDate || "").localeCompare(String(right.targetDate || ""));
      }
      if ((left.subjectIndex || 0) !== (right.subjectIndex || 0)) return (left.subjectIndex || 0) - (right.subjectIndex || 0);
      const leftSourceRank = sourceOrder[String(left.taskKind || left.source || "").trim().toLowerCase()] ?? 9;
      const rightSourceRank = sourceOrder[String(right.taskKind || right.source || "").trim().toLowerCase()] ?? 9;
      if (leftSourceRank !== rightSourceRank) return leftSourceRank - rightSourceRank;
      return String(left.subject || "").localeCompare(String(right.subject || ""));
    });
}

function buildGeneratedWeeklyTestTemplate({
  weekStartDate = "",
  grade = null,
  coveredTasks = [],
  priorWeekTasks = [],
  getQuiz,
  subjectsById = {},
  saturdayTestSettings = null,
}) {
  if (!weekStartDate || !Number.isFinite(Number(grade)) || typeof getQuiz !== "function") return null;
  const settings = normalizeAutoDiarySettings({ saturdayTest: saturdayTestSettings || {} }).saturdayTest;
  if (settings.enabled === false) return null;
  const accumulationMode = settings.accumulationMode || "rolling";
  const accumulationValue = settings.accumulationValue || 8;
  const hasPriorPool = Array.isArray(priorWeekTasks) && priorWeekTasks.length > 0;
  const truncateWeeklyTestText = (value, maxLength = 110) => {
    const safeValue = String(value || "").replace(/\s+/g, " ").trim();
    if (!safeValue) return "";
    return safeValue.length > maxLength ? `${safeValue.slice(0, maxLength - 3)}...` : safeValue;
  };
  const buildAnswerSnippet = (unit = {}) => {
    const title = truncateWeeklyTestText(unit?.sourceMeta?.title || unit?.title || "", 70);
    const detail = truncateWeeklyTestText(unit?.detail || unit?.title || "", 90);
    if (detail && normalizeText(detail) !== normalizeText(title)) return detail;
    return title || detail;
  };
  const extractBucket = (tasks, sourceTag, lessonIndexOffset) => {
    const uniqueLessons = new Map();
    (Array.isArray(tasks) ? tasks : []).forEach((task) => {
      if (!task || !task.subject || !task.lessonKey) return;
      const key = `${task.subject}::${task.lessonKey}::${String(task.contentId || "").trim() || "__default__"}`;
      if (uniqueLessons.has(key)) return;
      uniqueLessons.set(key, task);
    });
    const mcq = [];
    const tf = [];
    const fill = [];
    const pairs = [];
    const mcqSeen = new Set();
    const tfSeen = new Set();
    const fillSeen = new Set();
    const pairSeen = new Set();
    let lessonOrdinal = 0;
    uniqueLessons.forEach((task) => {
      const lessonIndex = lessonIndexOffset + lessonOrdinal;
      lessonOrdinal += 1;
      const quizRows = getQuiz(task.subject, grade, task.lessonKey);
      const safeQuizRows = Array.isArray(quizRows) ? quizRows : [];
      safeQuizRows.forEach((row, rowIndex) => {
        const prompt = String(row?.q || "").trim();
        const options = Array.isArray(row?.a) ? row.a.map((entry) => String(entry || "").trim()).filter(Boolean) : [];
        const correctIndex = Number(row?.c);
        if (prompt && options.length >= 2 && Number.isFinite(correctIndex) && correctIndex >= 0 && correctIndex < options.length) {
          const promptKey = `${sourceTag}::mcq::${normalizeText(prompt)}::${task.subject}::${task.lessonKey}`;
          if (!mcqSeen.has(promptKey)) {
            mcqSeen.add(promptKey);
            mcq.push({
              id: `${task.subject}_${task.lessonKey}_${sourceTag}_mcq_${lessonIndex}_${rowIndex}`,
              type: "mcq",
              prompt,
              options,
              correctIndex,
              subject: task.subject,
              lessonKey: task.lessonKey,
              source: sourceTag,
            });
          }
          const correctAnswer = truncateWeeklyTestText(options[correctIndex], 70);
          const wrongOption = truncateWeeklyTestText(options.find((entry, optionIndex) => optionIndex !== correctIndex && entry !== correctAnswer) || "", 70);
          const tfPrompt = `${prompt} -> ${(lessonIndex + rowIndex) % 2 === 0 || !wrongOption ? correctAnswer : wrongOption}`;
          const tfKey = `${sourceTag}::tf::${normalizeText(tfPrompt)}::${task.subject}::${task.lessonKey}`;
          if (!tfSeen.has(tfKey)) {
            tfSeen.add(tfKey);
            tf.push({
              id: `${task.subject}_${task.lessonKey}_${sourceTag}_tf_${lessonIndex}_${rowIndex}`,
              type: "truefalse",
              prompt: tfPrompt,
              correct: (lessonIndex + rowIndex) % 2 === 0 || !wrongOption,
              subject: task.subject,
              lessonKey: task.lessonKey,
              source: sourceTag,
            });
          }
        }
      });
      const lessonUnits = Array.isArray(task.taskUnits) && task.taskUnits.length
        ? task.taskUnits
        : extractLessonWorkUnits(task.lesson || task.chapterGroup?.activeLesson || {}, safeQuizRows);
      let lessonPairCount = 0;
      lessonUnits.forEach((unit, unitIndex) => {
        const unitTitle = truncateWeeklyTestText(unit?.sourceMeta?.title || unit?.title || "", 90);
        const unitAnswer = buildAnswerSnippet(unit);
        if (unitTitle && unitAnswer && normalizeText(unitTitle) !== normalizeText(unitAnswer)) {
          const fillKey = `${sourceTag}::fill::${normalizeText(unitTitle)}::${normalizeText(unitAnswer)}::${task.subject}::${task.lessonKey}`;
          if (!fillSeen.has(fillKey)) {
            fillSeen.add(fillKey);
            fill.push({
              id: `${task.subject}_${task.lessonKey}_${sourceTag}_fill_${lessonIndex}_${unitIndex}`,
              type: "fillblank",
              prompt: `${unitTitle}: _____`,
              answer: unitAnswer,
              subject: task.subject,
              lessonKey: task.lessonKey,
              source: sourceTag,
            });
          }
          const pairKey = `${normalizeText(unitTitle)}::${normalizeText(unitAnswer)}::${task.subject}::${task.lessonKey}`;
          if (!pairSeen.has(pairKey)) {
            pairSeen.add(pairKey);
            pairs.push({
              left: unitTitle,
              right: unitAnswer,
              id: `${task.subject}_${task.lessonKey}_${sourceTag}_pair_${lessonIndex}_${unitIndex}`,
              source: sourceTag,
            });
            lessonPairCount += 1;
          }
        }
      });
      if (!lessonPairCount) {
        const subject = subjectsById?.[task.subject] || null;
        const pairKey = `${normalizeText(subject?.name || task.subject)}::${normalizeText(task.title || task.lessonKey)}::fallback`;
        if (!pairSeen.has(pairKey)) {
          pairSeen.add(pairKey);
          pairs.push({
            left: subject?.name || task.subject,
            right: task.title || task.lessonKey,
            id: `${task.subject}_${task.lessonKey}_${sourceTag}_pair_${lessonIndex}_fallback`,
            source: sourceTag,
          });
        }
      }
    });
    return { mcq, tf, fill, pairs, lessonCount: uniqueLessons.size };
  };
  const currentBucket = extractBucket(coveredTasks, "current", 0);
  const priorBucket = hasPriorPool
    ? extractBucket(priorWeekTasks, "prior", currentBucket.lessonCount)
    : { mcq: [], tf: [], fill: [], pairs: [], lessonCount: 0 };
  const questions = [];
  const usedQuestionIds = new Set();
  const takeQuestions = (items, limit = 0) => {
    (Array.isArray(items) ? items : []).forEach((item) => {
      if (!item || !item.id || usedQuestionIds.has(item.id) || (limit > 0 && questions.length >= limit)) return;
      usedQuestionIds.add(item.id);
      questions.push(item);
    });
  };
  const difficultyQuestionCounts = {
    light: 8,
    standard: 10,
    rigorous: 12,
  };
  const targetQuestionCount = difficultyQuestionCounts[settings.difficulty] || difficultyQuestionCounts.standard;
  const desiredTypeCounts = (() => {
    const weightMap = settings.questionTypeWeights || {};
    const normalizedWeights = {
      mcq: Math.max(0, Number(weightMap.mcq) || 0),
      truefalse: Math.max(0, Number(weightMap.truefalse) || 0),
      fillblank: Math.max(0, Number(weightMap.fillblank) || 0),
      matching: Math.max(0, Number(weightMap.matching) || 0),
    };
    const totalWeight = Object.values(normalizedWeights).reduce((sum, value) => sum + value, 0) || 1;
    const counts = {};
    let usedCount = 0;
    ["mcq", "truefalse", "fillblank", "matching"].forEach((type, index, list) => {
      if (index === list.length - 1) {
        counts[type] = Math.max(0, targetQuestionCount - usedCount);
      } else {
        counts[type] = Math.max(0, Math.round((normalizedWeights[type] / totalWeight) * targetQuestionCount));
        usedCount += counts[type];
      }
    });
    return counts;
  })();
  const currentWeight = Math.max(0, Number(settings.currentWeekWeight) || 0);
  const priorWeight = Math.max(0, Number(settings.priorWeeksWeight) || 0);
  const totalWeekWeight = currentWeight + priorWeight || 1;
  const getPoolTakeCount = (desiredCount, source) => {
    if (!hasPriorPool || desiredCount <= 0) return source === "current" ? desiredCount : 0;
    if (source === "current") return Math.max(0, Math.round((currentWeight / totalWeekWeight) * desiredCount));
    return Math.max(0, desiredCount - Math.round((currentWeight / totalWeekWeight) * desiredCount));
  };
  const addWeightedType = (type, currentItems, priorItems) => {
    const desiredCount = desiredTypeCounts[type] || 0;
    if (desiredCount <= 0) return;
    takeQuestions((Array.isArray(currentItems) ? currentItems : []).slice(0, getPoolTakeCount(desiredCount, "current")), targetQuestionCount);
    takeQuestions((Array.isArray(priorItems) ? priorItems : []).slice(0, getPoolTakeCount(desiredCount, "prior")), targetQuestionCount);
  };
  addWeightedType("mcq", currentBucket.mcq, priorBucket.mcq);
  addWeightedType("truefalse", currentBucket.tf, priorBucket.tf);
  addWeightedType("fillblank", currentBucket.fill, priorBucket.fill);
  const desiredMatchingCount = desiredTypeCounts.matching || 0;
  const combinedPairs = [
    ...currentBucket.pairs.slice(0, Math.max(2, getPoolTakeCount(desiredMatchingCount, "current") * 2)),
    ...priorBucket.pairs.slice(0, Math.max(0, getPoolTakeCount(desiredMatchingCount, "prior") * 2)),
  ].slice(0, Math.max(3, desiredMatchingCount * 2));
  if (desiredMatchingCount > 0 && combinedPairs.length >= 3) {
    usedQuestionIds.add(`matching_${weekStartDate}`);
    questions.push({
      id: `matching_${weekStartDate}`,
      type: "matching",
      prompt: hasPriorPool
        ? "Match the covered lesson clues from this week and earlier weeks"
        : "Match the covered lesson clues from this week",
      pairs: combinedPairs,
      subject: "mixed",
      lessonKey: weekStartDate,
      source: hasPriorPool ? "mixed" : "current",
    });
  }
  const overflowPools = hasPriorPool
    ? [
      currentBucket.mcq,
      priorBucket.mcq,
      currentBucket.tf,
      priorBucket.tf,
      currentBucket.fill,
      priorBucket.fill,
    ]
    : [
      currentBucket.mcq,
      currentBucket.tf,
      currentBucket.fill,
    ];
  let overflowCursor = 0;
  while (questions.length < targetQuestionCount && overflowPools.some((pool) => Array.isArray(pool) && pool.length)) {
    const pool = overflowPools[overflowCursor % overflowPools.length];
    overflowCursor += 1;
    if (!Array.isArray(pool) || !pool.length) continue;
    const candidate = pool.shift();
    if (!candidate || usedQuestionIds.has(candidate.id)) continue;
    usedQuestionIds.add(candidate.id);
    questions.push(candidate);
  }
  if (!questions.length) return null;
  const accumulationScopeLabel = accumulationMode === "academic_year"
    ? "academic-year"
    : accumulationMode === "since_start"
      ? "since-app-start"
      : `rolling ${Math.max(1, Number(accumulationValue) || 8)}-week`;
  const instructions = hasPriorPool
    ? `Weekly test: ${currentWeight}% from this week's chapters and ${priorWeight}% from prior weeks (${accumulationScopeLabel} scope). Pool: ${currentBucket.lessonCount} current + ${priorBucket.lessonCount} prior lessons.`
    : `Weekly test from this week's chapters (${accumulationScopeLabel} scope - no prior weeks covered yet).`;
  const subjectScope = Array.from(new Set([
    ...(Array.isArray(coveredTasks) ? coveredTasks : []),
    ...(Array.isArray(priorWeekTasks) ? priorWeekTasks : []),
  ].map((task) => task?.subject).filter(Boolean)));
  return normalizeLocalTestTemplateRecord({
    templateId: `generated_${weekStartDate}_${grade}`,
    title: `Weekly Test - Grade ${grade}`,
    grade,
    subjectScope,
    payload: {
      title: `Weekly Test - Grade ${grade}`,
      instructions,
      questions,
    },
    source: "generated",
  });
}

function buildTestTemplateExportPayload(template) {
  const normalized = normalizeLocalTestTemplateRecord(template);
  if (!normalized) return null;
  return {
    kind: "homeschool-test-template",
    templateId: normalized.templateId,
    schoolId: normalized.schoolId,
    authorEmail: normalized.authorEmail,
    title: normalized.title,
    grade: normalized.grade,
    subjectScope: normalized.subjectScope,
    payload: normalized.payload,
  };
}

function buildTestTemplatePackExportPayload(templates = [], label = "Test Templates") {
  const normalizedTemplates = (Array.isArray(templates) ? templates : [])
    .map((template) => buildTestTemplateExportPayload(template))
    .filter(Boolean);
  return {
    kind: "homeschool-test-template-pack",
    label,
    templates: normalizedTemplates,
  };
}

function normalizeTestTemplateImportPayload(raw, context = {}) {
  const safe = raw && typeof raw === "object" ? raw : {};
  if (safe.kind === "homeschool-test-template-pack" || Array.isArray(safe.templates)) {
    return (Array.isArray(safe.templates) ? safe.templates : [])
      .map((entry, index) => normalizeLocalTestTemplateRecord({
        ...entry,
        grade: entry.grade || context.grade,
      }, index))
      .filter(Boolean);
  }
  const single = normalizeLocalTestTemplateRecord({
    ...safe,
    grade: safe.grade || context.grade,
  }, 0);
  return single ? [single] : [];
}

function buildEffectiveChapterAssignmentSelections(assignments = [], userEmail = "", targetGrade = null, canChooseContentSource = false) {
  if (canChooseContentSource || !Number.isFinite(Number(targetGrade))) return {};
  const safeUserEmail = String(userEmail || "").trim().toLowerCase();
  const gradeSelections = new Map();
  const studentSelections = new Map();
  (Array.isArray(assignments) ? assignments : []).forEach((assignment) => {
    const normalized = normalizeChapterAssignmentRecord(assignment);
    if (!normalized || normalized.status !== "active") return;
    if (Number(normalized.targetGrade) !== Number(targetGrade)) return;
    const baseKey = buildChapterSourcePreferenceKey(normalized.subject, normalized.targetGrade, normalized.lessonKey);
    if (normalized.targetType === "student") {
      if (!safeUserEmail || normalized.targetStudentEmail !== safeUserEmail) return;
      const previous = studentSelections.get(baseKey);
      if (!previous || normalized.updatedAt >= previous.assignment.updatedAt) {
        studentSelections.set(baseKey, {
          mode: "published",
          contentId: normalized.contentId,
          assignment: normalized,
        });
      }
      return;
    }
    const previous = gradeSelections.get(baseKey);
    if (!previous || normalized.updatedAt >= previous.assignment.updatedAt) {
      gradeSelections.set(baseKey, {
        mode: "published",
        contentId: normalized.contentId,
        assignment: normalized,
      });
    }
  });
  const nextSelections = {};
  gradeSelections.forEach((value, key) => {
    nextSelections[key] = value;
  });
  studentSelections.forEach((value, key) => {
    nextSelections[key] = value;
  });
  return nextSelections;
}

function getCanonicalLessonKeyForLesson(lesson) {
  if (!lesson || typeof lesson !== "object") return "";
  return resolveCustomChapterLessonKey({
    lessonKey: lesson?.publication?.canonicalLessonKey || lesson?.key || lesson?.id || "",
    title: lesson?.title || "",
  });
}

function getLessonVariantSourceType(lesson) {
  if (lesson?.__published) return "published";
  if (lesson?.__custom) return "custom";
  return "builtin";
}

function getLessonVariantIdentity(lesson) {
  const sourceType = getLessonVariantSourceType(lesson);
  const contentId = String(lesson?.publication?.contentId || lesson?.__contentId || "").trim();
  if (sourceType === "published" && contentId) return `published:${contentId}`;
  if (sourceType === "custom") return `custom:${getCanonicalLessonKeyForLesson(lesson)}`;
  return `builtin:${getCanonicalLessonKeyForLesson(lesson)}`;
}

function buildChapterVariantGroups({
  subjectId,
  targetGrade,
  baseLessons = [],
  customLessons = [],
  publishedLessons = [],
  preferences = {},
  assignmentSelections = {},
  currentUserId = "",
}) {
  const groups = [];
  const groupMap = new Map();
  const pushVariant = (lesson, sourceType, orderHint) => {
    if (!lesson || typeof lesson !== "object") return;
    const canonicalLessonKey = getCanonicalLessonKeyForLesson(lesson);
    if (!canonicalLessonKey) return;
    let group = groupMap.get(canonicalLessonKey);
    if (!group) {
      group = {
        subjectId: String(subjectId || "").trim(),
        grade: Number(targetGrade),
        canonicalLessonKey,
        orderHint: Number.isFinite(orderHint) ? orderHint : groups.length,
        title: lesson.title || canonicalLessonKey,
        variants: [],
      };
      groupMap.set(canonicalLessonKey, group);
      groups.push(group);
    }
    group.orderHint = Math.min(group.orderHint, Number.isFinite(orderHint) ? orderHint : group.orderHint);
    group.title = group.title || lesson.title || canonicalLessonKey;
    const sourceKey = getLessonVariantIdentity(lesson);
    if (group.variants.some((variant) => variant.sourceKey === sourceKey)) return;
    const contentId = String(lesson?.publication?.contentId || lesson?.__contentId || "").trim();
    const authorUserId = String(lesson?.publication?.authorUserId || lesson?.__contentOwnerId || "").trim();
    const authorUsername = String(lesson?.publication?.authorUsername || lesson?.__publishedBy || "").trim();
    group.variants.push({
      lesson,
      sourceType,
      sourceKey,
      contentId,
      authorUserId,
      authorUsername,
      forkedFromContentId: String(lesson?.publication?.forkedFromContentId || lesson?.__forkedFromContentId || "").trim(),
      ownedByCurrentUser: Boolean(currentUserId) && authorUserId === String(currentUserId || "").trim(),
      updatedAt: Number(lesson?.publication?.updatedAt || lesson?.publication?.publishedAt || 0) || 0,
    });
  };
  (Array.isArray(baseLessons) ? baseLessons : []).forEach((lesson, index) => pushVariant(lesson, "builtin", index));
  (Array.isArray(customLessons) ? customLessons : []).forEach((lesson, index) => pushVariant(lesson, "custom", 1000 + index));
  (Array.isArray(publishedLessons) ? publishedLessons : []).forEach((lesson, index) => pushVariant(lesson, "published", 2000 + index));
  return groups
    .map((group) => {
      const preferenceKey = buildChapterSourcePreferenceKey(group.subjectId, group.grade, group.canonicalLessonKey);
      const preference = preferences[preferenceKey] || { mode: "auto" };
      const assignmentSelection = assignmentSelections[preferenceKey] || null;
      const builtinVariant = group.variants.find((variant) => variant.sourceType === "builtin") || null;
      const customVariant = group.variants.find((variant) => variant.sourceType === "custom") || null;
      const publishedVariants = group.variants
        .filter((variant) => variant.sourceType === "published")
        .sort((left, right) => {
          if (left.ownedByCurrentUser !== right.ownedByCurrentUser) return left.ownedByCurrentUser ? -1 : 1;
          return (right.updatedAt || 0) - (left.updatedAt || 0);
        });
      let activeVariant = null;
      if (assignmentSelection?.mode === "published") {
        activeVariant = publishedVariants.find((variant) => variant.contentId === assignmentSelection.contentId)
          || null;
      }
      if (!activeVariant && preference.mode === "builtin") {
        activeVariant = builtinVariant;
      } else if (!activeVariant && preference.mode === "custom") {
        activeVariant = customVariant;
      } else if (!activeVariant && preference.mode === "published") {
        activeVariant = publishedVariants.find((variant) => variant.contentId === preference.contentId)
          || publishedVariants[0]
          || null;
      }
      if (!activeVariant) {
        activeVariant = customVariant
          || publishedVariants.find((variant) => variant.ownedByCurrentUser)
          || builtinVariant
          || publishedVariants[0]
          || group.variants[0]
          || null;
      }
      return {
        ...group,
        preferenceKey,
        preference,
        assignmentSelection,
        activeVariant,
        activeLesson: activeVariant?.lesson || null,
      };
    })
    .sort((left, right) => left.orderHint - right.orderHint || String(left.title || "").localeCompare(String(right.title || "")));
}

function getChapterVariantBadges(lesson, currentUserId, language) {
  const sourceType = getLessonVariantSourceType(lesson);
  const authorUserId = String(lesson?.publication?.authorUserId || lesson?.__contentOwnerId || "").trim();
  const badges = [];
  if (sourceType === "builtin") {
    badges.push({
      tone: "trust",
      label: joinLocalizedText("Verified", "مصدقہ", language),
    });
  } else if (sourceType === "custom") {
    badges.push({
      tone: "local",
      label: joinLocalizedText("Local", "مقامی", language),
    });
    if (String(lesson?.publication?.contentId || "").trim()) {
      badges.push({
        tone: authorUserId && authorUserId === String(currentUserId || "").trim() ? "mine" : "community",
        label: authorUserId && authorUserId === String(currentUserId || "").trim()
          ? joinLocalizedText("My copy", "میری نقل", language)
          : joinLocalizedText("Imported", "درآمد شدہ", language),
      });
    }
  } else if (sourceType === "published") {
    badges.push({
      tone: authorUserId && authorUserId === String(currentUserId || "").trim() ? "mine" : "community",
      label: authorUserId && authorUserId === String(currentUserId || "").trim()
        ? joinLocalizedText("My published", "میرا شائع شدہ", language)
        : joinLocalizedText("Community", "کمیونٹی", language),
    });
  }
  if (String(lesson?.publication?.forkedFromContentId || lesson?.__forkedFromContentId || "").trim()) {
    badges.push({
      tone: "fork",
      label: joinLocalizedText("Fork", "فورک", language),
    });
  }
  return badges;
}

function normalizeCustomChapterImportPayload(payload = {}, context = {}) {
  const safePayload = payload && typeof payload === "object" ? payload : {};
  const chapterPayload = safePayload.chapter && typeof safePayload.chapter === "object" ? safePayload.chapter : null;
  const lessonPayload = safePayload.lesson && typeof safePayload.lesson === "object"
    ? safePayload.lesson
    : safePayload.data && typeof safePayload.data === "object"
      ? safePayload.data
      : chapterPayload?.lesson && typeof chapterPayload.lesson === "object"
        ? chapterPayload.lesson
        : chapterPayload?.data && typeof chapterPayload.data === "object"
          ? chapterPayload.data
          : chapterPayload && typeof chapterPayload === "object"
            ? chapterPayload
            : {};
  const subject = String(context.subject || safePayload.subject || safePayload.meta?.subject || "").trim();
  const grade = Number(context.grade ?? safePayload.grade ?? safePayload.meta?.grade);
  const title = String(lessonPayload.title || safePayload.title || "").trim();
  const lessonKey = resolveCustomChapterLessonKey({
    lessonKey: safePayload.lessonKey || lessonPayload.key || lessonPayload.id,
    title,
    fallbackNumber: context.nextLessonNumber,
  });
  if (!subject || !Number.isFinite(grade)) {
    throw new Error("Chapter import needs a valid subject and grade.");
  }
  if (!lessonKey) {
    throw new Error("Chapter import needs a lesson key or title.");
  }
  const lessonData = cloneSerializableValue(lessonPayload) || {};
  delete lessonData.__custom;
  lessonData.key = lessonKey;
  lessonData.id = `${subject}_${grade}_${lessonKey}`;
  if (!lessonData.title) lessonData.title = title || lessonKey.replace(/_/g, " ");
  if (!lessonData.content && typeof safePayload.content === "string") lessonData.content = safePayload.content;
  if (!lessonData.title) {
    throw new Error("Chapter title is missing.");
  }
  const questions = Array.isArray(safePayload.questions)
    ? safePayload.questions
    : Array.isArray(safePayload.quiz)
      ? safePayload.quiz
      : Array.isArray(safePayload.quizQuestions)
        ? safePayload.quizQuestions
        : Array.isArray(chapterPayload?.questions)
          ? chapterPayload.questions
          : [];
  return {
    subject,
    grade,
    lessonKey,
    data: lessonData,
    questions: cloneSerializableValue(questions) || [],
  };
}

function normalizeCustomContentImportPayload(payload = {}, context = {}) {
  const safePayload = payload && typeof payload === "object" ? payload : {};
  const kind = String(safePayload.kind || "").trim().toLowerCase();
  const subjectMeta = safePayload.subject && typeof safePayload.subject === "object"
    ? normalizeSubjectDefinition(safePayload.subject)
    : null;
  const inheritedSubject = subjectMeta?.id || String(context.subject || safePayload.subject || safePayload.meta?.subject || "").trim().toLowerCase();
  const inheritedGrade = Number(context.grade ?? safePayload.grade ?? safePayload.meta?.grade);
  if (kind === "homeschool-subject-pack" || kind === "homeschool-chapter-pack" || Array.isArray(safePayload.chapters)) {
    const baseLessonNumber = Math.max(1, Number(context.nextLessonNumber) || 1);
    const chapters = (Array.isArray(safePayload.chapters) ? safePayload.chapters : []).map((entry, index) => normalizeCustomChapterImportPayload(entry, {
      subject: inheritedSubject,
      grade: inheritedGrade,
      nextLessonNumber: baseLessonNumber + index,
    }));
    return {
      kind: kind || (subjectMeta ? "homeschool-subject-pack" : "homeschool-chapter-pack"),
      subjects: subjectMeta?.id ? [subjectMeta] : [],
      chapters,
    };
  }
  return {
    kind: "homeschool-chapter",
    subjects: subjectMeta?.id ? [subjectMeta] : [],
    chapters: [normalizeCustomChapterImportPayload(safePayload, context)],
  };
}

