function createDefaultAiProviderConfigs() {
  return AI_PROVIDER_ORDER.reduce((acc, providerId) => {
    const definition = AI_PROVIDER_DEFS[providerId];
    acc[providerId] = {
      apiKey: "",
      model: definition.defaultModel,
      models: definition.modelHints.slice(),
      status: "empty",
      lastError: "",
      validatedAt: null,
    };
    return acc;
  }, {});
}

function sanitizeAiProviderConfigs(rawConfigs) {
  const defaults = createDefaultAiProviderConfigs();
  const source = rawConfigs && typeof rawConfigs === "object" ? rawConfigs : {};
  AI_PROVIDER_ORDER.forEach((providerId) => {
    const fallback = defaults[providerId];
    const raw = source[providerId] && typeof source[providerId] === "object" ? source[providerId] : {};
    defaults[providerId] = {
      apiKey: String(raw.apiKey || ""),
      model: String(raw.model || fallback.model),
      models: Array.isArray(raw.models) && raw.models.length > 0 ? raw.models.map((entry) => String(entry || "").trim()).filter(Boolean) : fallback.models.slice(),
      status: String(raw.status || (raw.apiKey ? "saved" : "empty")),
      lastError: String(raw.lastError || ""),
      validatedAt: raw.validatedAt || null,
    };
    if (!defaults[providerId].models.includes(defaults[providerId].model)) {
      defaults[providerId].models.unshift(defaults[providerId].model);
    }
  });
  return defaults;
}

function maskApiKey(value) {
  const trimmed = String(value || "").trim();
  if (!trimmed) return "";
  if (trimmed.length <= 8) return "••••••••";
  return `${trimmed.slice(0, 4)}••••••${trimmed.slice(-4)}`;
}

function canUseDirectAiFromBrowser() {
  if (window.location.protocol === "file:") {
    return { ok: false, reason: "file" };
  }
  const hostname = window.location.hostname || "";
  const isLocal = hostname === "localhost" || hostname === "127.0.0.1";
  if (window.location.protocol !== "https:" && !isLocal) {
    return { ok: false, reason: "insecure" };
  }
  return { ok: true, reason: null };
}

function buildTutorSystemPrompt(grade, language) {
  const replyHint = language === "ur"
    ? "Reply in Urdu."
    : language === "bilingual"
      ? "Use mostly English with Urdu support when helpful."
      : "Reply in English unless the student clearly asks for Urdu.";
  return `You are a friendly AI tutor named Ustaad for a Grade ${grade || 5} student in Pakistan. Explain simply, use Pakistani examples, keep responses concise (2-4 short paragraphs), and focus on helping the student understand the lesson. ${replyHint}`;
}

function normalizeAiModelList(providerId, models, preferredModel) {
  const definition = AI_PROVIDER_DEFS[providerId];
  const merged = new Set([...(definition?.modelHints || []), ...(Array.isArray(models) ? models : []), preferredModel || definition?.defaultModel]);
  return Array.from(merged).map((entry) => String(entry || "").trim()).filter(Boolean);
}

function normalizeWordMeaningPriority(value) {
  const raw = String(value || "").trim();
  if (WORD_MEANING_PRIORITY_OPTIONS.includes(raw)) return raw;
  if (raw === "ai-first") return "ai-cache-local";
  return "local-cache-ai";
}

function getWordMeaningSourceOrder(priorityValue) {
  return normalizeWordMeaningPriority(priorityValue).split("-").filter(Boolean);
}

function getOpenAiCompatibleMeta(providerId) {
  return OPENAI_COMPATIBLE_PROVIDER_META[providerId] || null;
}

function getOpenAiCompatibleHeaders(providerId, apiKey) {
  const headers = {
    "Content-Type": "application/json",
    "Authorization": `Bearer ${apiKey}`,
  };
  if (providerId === "openrouter") {
    headers["HTTP-Referer"] = window.location.origin || "https://naveedeme.github.io";
    headers["X-Title"] = "HomeSchool";
  }
  return headers;
}

function extractOpenAiCompatibleModels(data, providerId) {
  const meta = getOpenAiCompatibleMeta(providerId);
  const rawIds = Array.isArray(data?.data)
    ? data.data.map((entry) => String(entry?.id || entry?.name || "").trim()).filter(Boolean)
    : [];
  return typeof meta?.filterModels === "function" ? rawIds.filter((id) => meta.filterModels(id)) : rawIds;
}

async function validateOpenAiCompatibleProvider(providerId, apiKey, preferredModel) {
  const meta = getOpenAiCompatibleMeta(providerId);
  if (!meta) throw buildAiError("provider", "Provider metadata is missing.");
  const definition = AI_PROVIDER_DEFS[providerId];
  const model = preferredModel || definition.defaultModel;
  let discoveredModels = [];
  if (meta.modelsPath) {
    try {
      const data = await fetchJsonWithTimeout(`${meta.baseUrl}${meta.modelsPath}`, {
        headers: getOpenAiCompatibleHeaders(providerId, apiKey),
      });
      discoveredModels = extractOpenAiCompatibleModels(data, providerId);
    } catch (error) {
      // Fall back to validation via a tiny chat call if model listing is unavailable.
    }
  }
  await fetchJsonWithTimeout(`${meta.baseUrl}/chat/completions`, {
    method: "POST",
    headers: getOpenAiCompatibleHeaders(providerId, apiKey),
    body: JSON.stringify({
      model,
      max_tokens: 4,
      temperature: 0,
      messages: [
        { role: "system", content: "Reply with ok." },
        { role: "user", content: "ok" },
      ],
    }),
  });
  return {
    model,
    models: normalizeAiModelList(providerId, discoveredModels.length > 0 ? discoveredModels : definition.modelHints, model),
    status: "ready",
  };
}

function extractOpenAiText(content) {
  if (typeof content === "string") return content;
  if (Array.isArray(content)) {
    return content.map((entry) => {
      if (typeof entry === "string") return entry;
      if (typeof entry?.text === "string") return entry.text;
      return "";
    }).join("").trim();
  }
  return "";
}

function getMediaKindFromMimeType(mimeType) {
  const normalized = String(mimeType || "").toLowerCase();
  if (normalized.startsWith("image/")) return "image";
  if (normalized.startsWith("audio/")) return "audio";
  if (normalized.startsWith("video/")) return "video";
  return "file";
}

function buildInlineDataUrl(mimeType, base64Data) {
  const mime = String(mimeType || "").trim();
  const data = String(base64Data || "").trim();
  if (!mime || !data) return "";
  return `data:${mime};base64,${data}`;
}

function normalizeTutorMessageParts(parts, fallbackText = "") {
  const normalized = Array.isArray(parts)
    ? parts.map((part) => {
      if (!part || typeof part !== "object") return null;
      if (part.type === "media") {
        const mimeType = String(part.mimeType || "").trim();
        const mediaType = part.mediaType || getMediaKindFromMimeType(mimeType);
        const dataUrl = String(part.dataUrl || "").trim();
        const uri = String(part.uri || "").trim();
        if (!mimeType || (!dataUrl && !uri)) return null;
        return {
          type: "media",
          mediaType,
          mimeType,
          dataUrl,
          uri,
          fileName: String(part.fileName || "").trim(),
          size: Number(part.size) || 0,
          persistable: Boolean(part.persistable),
        };
      }
      const text = String(part.text || "").trim();
      if (!text) return null;
      return { type: "text", text };
    }).filter(Boolean)
    : [];
  if (normalized.length > 0) return normalized;
  const text = String(fallbackText || "").trim();
  return text ? [{ type: "text", text }] : [];
}

function flattenTutorMessageText(message) {
  if (!message || typeof message !== "object") return "";
  const parts = Array.isArray(message.parts) ? message.parts : [];
  const textFromParts = parts.filter((part) => part?.type === "text" && String(part.text || "").trim()).map((part) => String(part.text).trim()).join("\n\n").trim();
  if (textFromParts) return textFromParts;
  return String(message.text || "").trim();
}

function sanitizeTutorMessageForStorage(message) {
  const normalizedParts = normalizeTutorMessageParts(message?.parts, message?.text);
  return {
    role: message?.role === "user" ? "user" : "ai",
    text: flattenTutorMessageText({ parts: normalizedParts, text: message?.text }),
    provider: message?.provider ? String(message.provider) : "",
    createdAt: Number(message?.createdAt) || Date.now(),
    parts: normalizedParts.map((part) => {
      if (part.type !== "media") return part;
      const keepData = part.persistable && String(part.dataUrl || "").length > 0 && String(part.dataUrl || "").length <= 180000;
      return {
        type: "media",
        mediaType: part.mediaType,
        mimeType: part.mimeType,
        fileName: part.fileName,
        size: Number(part.size) || 0,
        persistable: Boolean(part.persistable),
        dataUrl: keepData ? part.dataUrl : "",
        uri: keepData ? "" : String(part.uri || "").trim(),
      };
    }),
  };
}

function extractGeminiResponseParts(data) {
  return (data?.candidates || [])
    .flatMap((candidate) => candidate?.content?.parts || [])
    .map((part) => {
      const text = String(part?.text || "").trim();
      if (text) return { type: "text", text };
      const inline = part?.inlineData || part?.inline_data || null;
      const fileData = part?.fileData || part?.file_data || null;
      const mimeType = String(inline?.mimeType || inline?.mime_type || fileData?.mimeType || fileData?.mime_type || "").trim();
      const base64Data = String(inline?.data || "").trim();
      const uri = String(fileData?.fileUri || fileData?.file_uri || "").trim();
      if (!mimeType || (!base64Data && !uri)) return null;
      return {
        type: "media",
        mediaType: getMediaKindFromMimeType(mimeType),
        mimeType,
        dataUrl: base64Data ? buildInlineDataUrl(mimeType, base64Data) : "",
        uri,
        fileName: "",
        size: 0,
        persistable: Boolean(base64Data) && base64Data.length <= 180000,
      };
    })
    .filter(Boolean);
}

function extractGeminiText(data) {
  return extractGeminiResponseParts(data)
    .filter((part) => part.type === "text")
    .map((part) => part.text || "")
    .join("")
    .trim();
}

function buildAiError(code, message, status = null) {
  const error = new Error(message);
  error.code = code;
  error.status = status;
  return error;
}

function getAiErrorCode(error) {
  return String(error?.code || "unknown");
}

function getAiStatusFromError(error) {
  const code = getAiErrorCode(error);
  if (code === "auth") return "auth";
  if (code === "blocked") return "blocked";
  if (code === "rate_limit") return "quota";
  return "error";
}

function getFriendlyAiErrorMessage(providerId, error, language) {
  const provider = AI_PROVIDER_DEFS[providerId];
  const providerName = joinLocalizedText(provider?.name || providerId, provider?.nameUr || provider?.name || providerId, language);
  const code = getAiErrorCode(error);
  if (code === "auth") {
    return joinLocalizedText(`${providerName} key is invalid or no longer authorized.`, `${providerName} کی درست نہیں ہے یا اب مجاز نہیں رہی۔`, language);
  }
  if (code === "rate_limit") {
    return providerId === "openai"
      ? joinLocalizedText("OpenAI API billing or quota is required for this key.", "اس OpenAI کی کے لیے API بلنگ یا کوٹہ درکار ہے۔", language)
      : joinLocalizedText(`${providerName} quota or rate limit was reached.`, `${providerName} کا کوٹہ یا ریٹ لمٹ پوری ہو گئی ہے۔`, language);
  }
  if (code === "blocked") {
    return providerId === "ollama"
      ? joinLocalizedText("Ollama Cloud is blocking direct browser access from this site.", "Ollama Cloud اس سائٹ سے براہِ راست براؤزر رسائی کو بلاک کر رہا ہے۔", language)
      : joinLocalizedText(`${providerName} is blocking direct browser access from this site.`, `${providerName} اس سائٹ سے براہِ راست براؤزر رسائی کو بلاک کر رہا ہے۔`, language);
  }
  if (code === "timeout") {
    return joinLocalizedText(`${providerName} took too long to respond.`, `${providerName} نے جواب دینے میں بہت وقت لیا۔`, language);
  }
  return error?.message || joinLocalizedText(`${providerName} could not be reached right now.`, `${providerName} تک اس وقت رسائی نہیں ہو سکی۔`, language);
}

function isAiProviderReady(config) {
  return Boolean(String(config?.apiKey || "").trim()) && config?.status === "ready";
}

async function fetchJsonWithTimeout(url, options = {}, timeoutMs = 20000) {
  const controller = typeof AbortController !== "undefined" ? new AbortController() : null;
  const timeout = controller ? setTimeout(() => controller.abort(), timeoutMs) : null;
  try {
    const response = await fetch(url, {
      ...options,
      signal: controller ? controller.signal : options.signal,
    });
    const text = await response.text();
    let data = null;
    try {
      data = text ? JSON.parse(text) : null;
    } catch {
      data = { raw: text };
    }
    if (!response.ok) {
      const message = data?.error?.message || data?.message || data?.raw || `Request failed with status ${response.status}.`;
      if (response.status === 401 || response.status === 403) throw buildAiError("auth", message, response.status);
      if (response.status === 429) throw buildAiError("rate_limit", message, response.status);
      throw buildAiError("provider", message, response.status);
    }
    return data;
  } catch (error) {
    if (error?.name === "AbortError") throw buildAiError("timeout", "The request timed out.");
    if (error?.code) throw error;
    if (error instanceof TypeError) throw buildAiError("blocked", "The browser blocked the request or the provider did not allow this origin.");
    throw buildAiError("unknown", error?.message || "Unknown AI request error.");
  } finally {
    if (timeout) clearTimeout(timeout);
  }
}

function readFileAsDataUrl(file) {
  return new Promise((resolve, reject) => {
    try {
      const reader = new FileReader();
      reader.onload = () => resolve(String(reader.result || ""));
      reader.onerror = () => reject(reader.error || new Error("Failed to read file."));
      reader.readAsDataURL(file);
    } catch (error) {
      reject(error);
    }
  });
}

async function validateAiProviderConfig(providerId, apiKey, preferredModel) {
  const browserCapability = canUseDirectAiFromBrowser();
  if (!browserCapability.ok) {
    throw buildAiError("blocked", browserCapability.reason === "file"
      ? "Browser AI access is blocked in direct file mode. Use the published HTTPS site or localhost."
      : "Browser AI access needs HTTPS or localhost.");
  }
  const openAiMeta = getOpenAiCompatibleMeta(providerId);
  if (openAiMeta) {
    return validateOpenAiCompatibleProvider(providerId, apiKey, preferredModel);
  }
  if (providerId === "anthropic") {
    await fetchJsonWithTimeout("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-api-key": apiKey,
        "anthropic-version": "2023-06-01",
        "anthropic-dangerous-direct-browser-access": "true",
      },
      body: JSON.stringify({
        model: preferredModel || AI_PROVIDER_DEFS.anthropic.defaultModel,
        max_tokens: 4,
        system: "Reply with ok.",
        messages: [{ role: "user", content: "ok" }],
      }),
    });
    return {
      model: preferredModel || AI_PROVIDER_DEFS.anthropic.defaultModel,
      models: normalizeAiModelList(providerId, AI_PROVIDER_DEFS.anthropic.modelHints, preferredModel),
      status: "ready",
    };
  }
  if (providerId === "gemini") {
    const data = await fetchJsonWithTimeout(`https://generativelanguage.googleapis.com/v1beta/models?key=${encodeURIComponent(apiKey)}`, {
      headers: {
        "Content-Type": "application/json",
      },
    });
    const models = normalizeAiModelList(providerId, (data?.models || [])
      .filter((entry) => Array.isArray(entry?.supportedGenerationMethods) && entry.supportedGenerationMethods.includes("generateContent"))
      .map((entry) => String(entry?.name || "").replace(/^models\//, "")), preferredModel);
    return {
      model: preferredModel || AI_PROVIDER_DEFS.gemini.defaultModel,
      models,
      status: "ready",
    };
  }
  const data = await fetchJsonWithTimeout("https://ollama.com/api/tags", {
    headers: {
      "Authorization": `Bearer ${apiKey}`,
    },
  });
  return {
    model: preferredModel || AI_PROVIDER_DEFS.ollama.defaultModel,
    models: normalizeAiModelList(providerId, (data?.models || []).map((entry) => entry.name || entry.model), preferredModel),
    status: "ready",
  };
}

async function requestAiTutorResponse(providerId, apiKey, model, conversation, systemPrompt) {
  const result = await requestAiTutorTurn(providerId, apiKey, model, conversation, systemPrompt);
  return result?.text || "Sorry, I could not generate a reply.";
}

async function requestGeminiWordMeaning(apiKey, model, word) {
  const browserCapability = canUseDirectAiFromBrowser();
  if (!browserCapability.ok) {
    throw buildAiError("blocked", browserCapability.reason === "file"
      ? "Browser AI access is blocked in direct file mode. Open the HTTPS published site or localhost."
      : "Browser AI access needs HTTPS or localhost.");
  }
  const data = await fetchJsonWithTimeout(`https://generativelanguage.googleapis.com/v1beta/models/${encodeURIComponent(model)}:generateContent?key=${encodeURIComponent(apiKey)}`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify({
      systemInstruction: {
        parts: [{
          text: "You are a bilingual dictionary helper for Pakistani school students. Return valid JSON only. Use exactly these keys: meaningsUr, simpleExplanationUr, meaningsEn, explanationEng, examplesEng. meaningsUr must be an ordered array of 3 to 6 short Urdu meanings in Urdu script only. simpleExplanationUr must be one short, very easy Urdu explanation. meaningsEn must be an ordered array of 1 to 4 short English sense labels. explanationEng must be one short plain-English explanation. examplesEng must be an array of 1 to 3 short classroom-friendly English example sentences. No markdown. No extra keys.",
        }],
      },
      contents: [{
        role: "user",
        parts: [{
          text: `English word: "${String(word || "").trim()}". Return JSON only.`,
        }],
      }],
      generationConfig: {
        temperature: 0.2,
        responseMimeType: "application/json",
      },
    }),
  });
  const text = extractGeminiText(data).trim();
  return extractWordMeaningDetails(text);
}

async function requestAiTutorTurn(providerId, apiKey, model, conversation, systemPrompt) {
  const browserCapability = canUseDirectAiFromBrowser();
  if (!browserCapability.ok) {
    throw buildAiError("blocked", browserCapability.reason === "file"
      ? "Browser AI access is blocked in direct file mode. Open the HTTPS published site or localhost."
      : "Browser AI access needs HTTPS or localhost.");
  }
  const messages = conversation.map((entry) => ({
    role: entry.role === "ai" ? "assistant" : "user",
    content: flattenTutorMessageText(entry),
    parts: normalizeTutorMessageParts(entry?.parts, entry?.text),
  }));
  const openAiMeta = getOpenAiCompatibleMeta(providerId);
  if (openAiMeta) {
    const data = await fetchJsonWithTimeout(`${openAiMeta.baseUrl}/chat/completions`, {
      method: "POST",
      headers: getOpenAiCompatibleHeaders(providerId, apiKey),
      body: JSON.stringify({
        model,
        temperature: 0.4,
        messages: [{ role: "system", content: systemPrompt }, ...messages.map((entry) => ({ role: entry.role, content: entry.content }))],
      }),
    });
    const text = extractOpenAiText(data?.choices?.[0]?.message?.content) || "Sorry, I could not generate a reply.";
    return { text, parts: [{ type: "text", text }] };
  }
  if (providerId === "anthropic") {
    const data = await fetchJsonWithTimeout("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-api-key": apiKey,
        "anthropic-version": "2023-06-01",
        "anthropic-dangerous-direct-browser-access": "true",
      },
      body: JSON.stringify({
        model,
        max_tokens: 800,
        system: systemPrompt,
        messages: messages.map((entry) => ({
          role: entry.role === "assistant" ? "assistant" : "user",
          content: entry.content,
        })),
      }),
    });
    const text = (data?.content || []).map((entry) => entry?.text || "").join("").trim() || "Sorry, I could not generate a reply.";
    return { text, parts: [{ type: "text", text }] };
  }
  if (providerId === "gemini") {
    const data = await fetchJsonWithTimeout(`https://generativelanguage.googleapis.com/v1beta/models/${encodeURIComponent(model)}:generateContent?key=${encodeURIComponent(apiKey)}`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        systemInstruction: {
          parts: [{ text: systemPrompt }],
        },
        contents: messages.map((entry) => ({
          role: entry.role === "assistant" ? "model" : "user",
          parts: entry.parts.map((part) => part.type === "media"
            ? {
              inlineData: {
                mimeType: part.mimeType,
                data: String(part.dataUrl || "").split(",")[1] || "",
              },
            }
            : { text: part.text }),
        })),
        generationConfig: {
          temperature: 0.4,
        },
      }),
    });
    const parts = extractGeminiResponseParts(data);
    const text = parts.filter((part) => part.type === "text").map((part) => part.text).join("").trim();
    if (parts.length > 0) {
      return { text, parts };
    }
    return { text: "Sorry, I could not generate a reply.", parts: [{ type: "text", text: "Sorry, I could not generate a reply." }] };
  }
  const data = await fetchJsonWithTimeout("https://ollama.com/api/chat", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model,
      stream: false,
      messages: [{ role: "system", content: systemPrompt }, ...messages.map((entry) => ({ role: entry.role, content: entry.content }))],
    }),
  });
  const text = data?.message?.content || data?.response || "Sorry, I could not generate a reply.";
  return { text, parts: [{ type: "text", text }] };
}

function getLocalizedNamePair(studentName, studentNameUr) {
  return {
    en: String(studentName || studentNameUr || "").trim(),
    ur: String(studentNameUr || studentName || "").trim(),
  };
}

function createStudentProfileDraft(base = {}) {
  const now = Date.now();
  const id = String(base.id || `profile_${now}_${Math.random().toString(36).slice(2, 8)}`).trim();
  return {
    id,
    nickname: String(base.nickname || base.profileNickname || "").trim(),
    grade: typeof base.grade !== "undefined" && base.grade !== null ? Number(base.grade) : null,
    studentName: String(base.studentName || base.name || "").trim(),
    studentNameUr: String(base.studentNameUr || base.nameUr || "").trim(),
    role: ["student", "parent", "teacher"].includes(base.role) ? base.role : "student",
    createdAt: Number(base.createdAt) || now,
    updatedAt: Number(base.updatedAt) || now,
  };
}

function normalizeStudentProfiles(profiles = [], fallbackProfile = {}) {
  const safeProfiles = Array.isArray(profiles) ? profiles : [];
  const normalized = safeProfiles
    .map((profile) => createStudentProfileDraft(profile))
    .filter((profile, index, list) => profile.id && list.findIndex((entry) => entry.id === profile.id) === index);
  if (normalized.length) return normalized;
  return [createStudentProfileDraft(fallbackProfile)];
}

function normalizeDeletedStudentProfileIds(value = []) {
  return Array.from(new Set((Array.isArray(value) ? value : [])
    .map((entry) => String(entry || "").trim())
    .filter(Boolean)));
}

function filterProfilesByDeletedIds(profiles = [], deletedIds = [], fallbackProfile = {}) {
  const deletedSet = new Set(normalizeDeletedStudentProfileIds(deletedIds));
  const visibleProfiles = normalizeStudentProfiles(profiles, fallbackProfile)
    .filter((profile) => !deletedSet.has(String(profile.id || "").trim()));
  if (visibleProfiles.length) return visibleProfiles;
  return [createStudentProfileDraft(fallbackProfile)];
}

function resolveActiveStudentProfileId(profiles = [], preferredId = "") {
  const safeProfiles = Array.isArray(profiles) ? profiles : [];
  const matched = safeProfiles.find((profile) => profile.id === preferredId);
  return matched?.id || safeProfiles[0]?.id || "";
}

function getStudentProfileDisplayName(profile = {}, language = "en") {
  const safeProfile = createStudentProfileDraft(profile);
  const primary = String(safeProfile.nickname || "").trim();
  const fallbackEn = String(safeProfile.studentName || "").trim();
  const fallbackUr = String(safeProfile.studentNameUr || "").trim();
  if (language === "ur") return primary || fallbackUr || fallbackEn || "طالب علم";
  if (language === "bilingual") {
    if (primary && (fallbackEn || fallbackUr)) {
      return joinLocalizedText(primary, fallbackUr || fallbackEn || primary, language);
    }
    return joinLocalizedText(fallbackEn || primary || "Student", fallbackUr || primary || fallbackEn || "طالب علم", language);
  }
  return primary || fallbackEn || fallbackUr || "Student";
}

function getStudentProfileInitials(profile = {}) {
  const safeProfile = createStudentProfileDraft(profile);
  const seed = String(safeProfile.nickname || safeProfile.studentName || safeProfile.studentNameUr || "S").trim();
  const parts = seed.replace(/\s+/g, " ").split(" ").filter(Boolean);
  if (parts.length >= 2) {
    return `${parts[0][0] || ""}${parts[1][0] || ""}`.toUpperCase();
  }
  return seed.slice(0, 2).toUpperCase();
}

function sanitizeAccountUsername(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9._-]/g, "")
    .slice(0, 32);
}

function stableSerialize(value) {
  if (Array.isArray(value)) return value.map(stableSerialize);
  if (!value || typeof value !== "object") return value;
  return Object.keys(value).sort().reduce((acc, key) => {
    acc[key] = stableSerialize(value[key]);
    return acc;
  }, {});
}

function getCloudConflictTitle(dataset, rowId, payload = {}, language = "en") {
  const safeDataset = String(dataset || "").trim();
  if (safeDataset === "customization") {
    const type = String(payload?.type || rowId || "").trim();
    const labels = {
      preferences: ["Display & navigation settings", "ڈسپلے اور نیویگیشن سیٹنگز"],
      audioPreferences: ["Audio settings", "آڈیو سیٹنگز"],
      reviewPreferences: ["Review settings", "ریویو سیٹنگز"],
      contentPreferences: ["Chapter source preferences", "سبق ماخذ ترجیحات"],
      practiceProgress: ["Practice progress", "پریکٹس پیش رفت"],
      reminderSettings: ["Reminder settings", "یاد دہانی سیٹنگز"],
      classScheduleSettings: ["Class schedule", "کلاس شیڈول"],
      studentProfiles: ["Student profiles", "طالب علم پروفائل"],
      activeStudentProfileId: ["Active profile", "فعال پروفائل"],
      accountPreferences: ["Account preferences", "اکاؤنٹ ترجیحات"],
    };
    const pair = labels[type] || ["Settings change", "سیٹنگ تبدیلی"];
    return joinLocalizedText(pair[0], pair[1], language);
  }
  if (safeDataset === "wordMeta") {
    return joinLocalizedText("Favorite / note", "پسندیدہ / نوٹ", language);
  }
  if (safeDataset === "customList") {
    return joinLocalizedText("Custom list", "کسٹم فہرست", language);
  }
  if (safeDataset === "customListItem") {
    return joinLocalizedText("Custom list item", "کسٹم فہرست آئٹم", language);
  }
  if (safeDataset === "progress" || safeDataset === "reviewCard" || safeDataset === "reviewHistory") {
    return joinLocalizedText("Review progress", "ریویو پیش رفت", language);
  }
  if (safeDataset === "userStat") {
    return joinLocalizedText("Study totals", "مطالعہ مجموعے", language);
  }
  return `${safeDataset} • ${rowId}`;
}

function sanitizeUrduInput(value) {
  return String(value || "")
    .replace(/[^\u0600-\u06FF\u0750-\u077F\u08A0-\u08FF\s\u060C\u061B\u061F\u0640\u0660-\u0669\u06F0-\u06F9]/g, "")
    .replace(/\s{2,}/g, " ")
    .trimStart();
}

function containsUrduText(value) {
  return /[\u0600-\u06FF\u0750-\u077F\u08A0-\u08FF]/.test(String(value || ""));
}

const WORD_LOOKUP_STOPWORDS = new Set([
  "a", "an", "and", "are", "as", "at", "be", "by", "for", "from", "had", "has", "have", "he", "her", "him",
  "his", "i", "in", "is", "it", "its", "me", "my", "of", "on", "or", "our", "she", "so", "than", "that", "the",
  "their", "them", "there", "these", "they", "this", "to", "too", "was", "we", "were", "will", "with", "you",
  "your",
]);

function normalizeLookupWord(word) {
  return String(word || "")
    .toLowerCase()
    .replace(/[’]/g, "'")
    .replace(/^[^a-z]+|[^a-z]+$/g, "")
    .trim();
}

function getLookupWordCandidates(word) {
  const base = normalizeLookupWord(word);
  const candidates = new Set();
  if (!base) return [];
  const pushCandidate = (value) => {
    const normalized = normalizeLookupWord(value);
    if (normalized) candidates.add(normalized);
  };
  pushCandidate(base);
  if (base.endsWith("'s")) pushCandidate(base.slice(0, -2));
  if (base.endsWith("ies") && base.length > 4) pushCandidate(`${base.slice(0, -3)}y`);
  if (base.endsWith("ing") && base.length > 5) {
    pushCandidate(base.slice(0, -3));
    pushCandidate(`${base.slice(0, -3)}e`);
    if (/(.)\1$/.test(base.slice(0, -3))) pushCandidate(base.slice(0, -4));
  }
  if (base.endsWith("ied") && base.length > 4) pushCandidate(`${base.slice(0, -3)}y`);
  if (base.endsWith("ed") && base.length > 4) {
    pushCandidate(base.slice(0, -2));
    pushCandidate(`${base.slice(0, -2)}e`);
    if (/(.)\1$/.test(base.slice(0, -2))) pushCandidate(base.slice(0, -3));
  }
  if (base.endsWith("es") && base.length > 4) pushCandidate(base.slice(0, -2));
  if (base.endsWith("s") && base.length > 3) pushCandidate(base.slice(0, -1));
  if (base.endsWith("er") && base.length > 4) pushCandidate(base.slice(0, -2));
  if (base.endsWith("est") && base.length > 5) pushCandidate(base.slice(0, -3));
  return Array.from(candidates);
}

function normalizeMeaningList(value, max = 6) {
  if (Array.isArray(value)) {
    return Array.from(new Set(value.map((entry) => String(entry || "").trim()).filter(Boolean))).slice(0, max);
  }
  const text = String(value || "").trim();
  return text ? [text] : [];
}

function normalizeExampleList(value, max = 4) {
  return normalizeMeaningList(value, max);
}

function choosePreferredText(currentValue, nextValue) {
  const currentText = String(currentValue || "").trim();
  const nextText = String(nextValue || "").trim();
  if (!currentText) return nextText;
  if (!nextText) return currentText;
  return nextText.length >= currentText.length ? nextText : currentText;
}

function normalizeWordMeaningEntry(rawWord, value, options = {}) {
  const candidateWord = String(rawWord || value?.word || value?.normalizedWord || "").trim();
  const normalizedWord = normalizeLookupWord(candidateWord);
  if (!normalizedWord || !value || typeof value !== "object") return null;
  const meaningsUr = normalizeMeaningList(value.meaningsUr || value.meaningUr || value.meaning || value.translationUr);
  const explanationUr = String(value.explanationUr || value.simpleExplanationUr || "").trim();
  const meaningsEn = normalizeMeaningList(value.meaningsEn || value.meaningEn || value.translationEn);
  const explanationEng = String(value.explanationEng || value.simpleExplanationEng || "").trim();
  const examplesEng = normalizeExampleList(value.examplesEng || value.examplesEn || value.examples);
  const sources = Array.from(new Set([
    ...(Array.isArray(value.sources) ? value.sources : []),
    String(value.source || options.defaultSource || "").trim(),
  ].map((entry) => String(entry || "").trim()).filter(Boolean)));
  const origins = Array.from(new Set([
    ...(Array.isArray(value.origins) ? value.origins : []),
    String(value.origin || "").trim(),
    ...(Array.isArray(options.defaultOrigins) ? options.defaultOrigins : []),
  ].map((entry) => String(entry || "").trim().toLowerCase()).filter(Boolean)));
  const meaningUr = meaningsUr[0] || "";
  if (!meaningUr && !explanationUr && !meaningsEn.length && !explanationEng && !examplesEng.length) return null;
  const now = Date.now();
  return {
    word: String(value.word || rawWord || normalizedWord).trim() || normalizedWord,
    normalizedWord,
    meaningUr,
    meaningsUr,
    explanationUr,
    meaningsEn,
    explanationEng,
    examplesEng,
    partOfSpeech: String(value.partOfSpeech || "").trim(),
    source: sources[0] || String(options.defaultSource || value.source || "cache").trim() || "cache",
    sources,
    origins,
    deletedAt: value.deletedAt ? (Number(value.deletedAt) || Date.now()) : null,
    fetchedAt: Number(value.fetchedAt) || Number(value.updatedAt) || now,
    createdAt: Number(value.createdAt) || Number(value.fetchedAt) || now,
    updatedAt: Number(value.updatedAt) || Number(value.fetchedAt) || now,
  };
}

function mergeWordMeaningEntry(baseEntry, nextEntry) {
  const base = baseEntry && typeof baseEntry === "object" ? baseEntry : null;
  const next = nextEntry && typeof nextEntry === "object" ? nextEntry : null;
  if (!base && !next) return null;
  if (!base) return next;
  if (!next) return base;
  const meaningsUr = Array.from(new Set([...(base.meaningsUr || []), ...(next.meaningsUr || [])].filter(Boolean))).slice(0, 6);
  const meaningsEn = Array.from(new Set([...(base.meaningsEn || []), ...(next.meaningsEn || [])].filter(Boolean))).slice(0, 6);
  const examplesEng = Array.from(new Set([...(base.examplesEng || []), ...(next.examplesEng || [])].filter(Boolean))).slice(0, 4);
  const sources = Array.from(new Set([...(base.sources || []), ...(next.sources || []), base.source, next.source].filter(Boolean)));
  const origins = Array.from(new Set([...(base.origins || []), ...(next.origins || [])].filter(Boolean)));
  const merged = {
    ...base,
    ...next,
    word: String(next.word || base.word || "").trim() || String(next.normalizedWord || base.normalizedWord || ""),
    normalizedWord: next.normalizedWord || base.normalizedWord,
    meaningsUr,
    meaningUr: meaningsUr[0] || String(next.meaningUr || base.meaningUr || "").trim(),
    explanationUr: choosePreferredText(base.explanationUr, next.explanationUr),
    meaningsEn,
    explanationEng: choosePreferredText(base.explanationEng, next.explanationEng),
    examplesEng,
    partOfSpeech: String(next.partOfSpeech || base.partOfSpeech || "").trim(),
    source: next.source || base.source || sources[0] || "cache",
    sources,
    origins,
    deletedAt: Object.prototype.hasOwnProperty.call(next, "deletedAt")
      ? (next.deletedAt ? Number(next.deletedAt) || Date.now() : null)
      : (base.deletedAt || null),
    createdAt: Math.min(Number(base.createdAt) || Date.now(), Number(next.createdAt) || Date.now()),
    fetchedAt: Math.max(Number(base.fetchedAt) || 0, Number(next.fetchedAt) || 0, Date.now()),
    updatedAt: Math.max(Number(base.updatedAt) || 0, Number(next.updatedAt) || 0, Date.now()),
  };
  return merged;
}

function normalizeWordMeaningCache(rawCache, options = {}) {
  if (!rawCache) return {};
  let pairs = [];
  if (Array.isArray(rawCache)) {
    pairs = rawCache.map((entry) => [entry?.normalizedWord || entry?.word, entry]);
  } else if (rawCache && typeof rawCache === "object" && Array.isArray(rawCache.entries)) {
    pairs = rawCache.entries.map((entry) => [entry?.normalizedWord || entry?.word, entry]);
  } else if (rawCache && typeof rawCache === "object") {
    pairs = Object.entries(rawCache);
  }
  return pairs.reduce((acc, [key, value]) => {
    const normalizedEntry = normalizeWordMeaningEntry(key, value, options);
    if (!normalizedEntry) return acc;
    const normalizedKey = normalizedEntry.normalizedWord;
    acc[normalizedKey] = mergeWordMeaningEntry(acc[normalizedKey], normalizedEntry);
    return acc;
  }, {});
}

function mergeWordMeaningMaps(...maps) {
  return maps.reduce((acc, map) => {
    const normalizedMap = normalizeWordMeaningCache(map || {});
    Object.entries(normalizedMap).forEach(([key, value]) => {
      acc[key] = mergeWordMeaningEntry(acc[key], value);
    });
    return acc;
  }, {});
}

function removeDictionaryEntriesFromMap(rawCache, normalizedWords = []) {
  const nextMap = { ...normalizeWordMeaningCache(rawCache || {}) };
  (Array.isArray(normalizedWords) ? normalizedWords : []).forEach((value) => {
    const normalized = normalizeLookupWord(value);
    if (normalized) delete nextMap[normalized];
  });
  return nextMap;
}

const DICTIONARY_SOURCE_PRIORITY = {
  curriculum: 40,
  imported: 32,
  trusted: 30,
  user: 24,
  manual: 22,
  gemini: 14,
  ai: 12,
  cache: 8,
  local: 6,
};

function getDictionaryEntryPriority(entry) {
  if (!entry || typeof entry !== "object") return 0;
  const sourceKeys = []
    .concat(Array.isArray(entry.origins) ? entry.origins : [])
    .concat(Array.isArray(entry.sources) ? entry.sources : [])
    .concat([entry.origin, entry.source])
    .map((value) => String(value || "").trim().toLowerCase())
    .filter(Boolean);
  return sourceKeys.reduce((best, key) => Math.max(best, DICTIONARY_SOURCE_PRIORITY[key] || 0), 0);
}

function normalizeComparableMeaning(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/[،,:;'"`~!@#$%^&*()_+=[\]{}\\|<>/?.-]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function getDictionaryMeaningCore(entry) {
  return Array.from(new Set([
    ...(Array.isArray(entry?.meaningsUr) ? entry.meaningsUr : []),
    entry?.meaningUr || "",
  ]
    .map((value) => normalizeComparableMeaning(value))
    .filter(Boolean)));
}

function hasMeaningIntersection(leftEntry, rightEntry) {
  const left = new Set(getDictionaryMeaningCore(leftEntry));
  const right = getDictionaryMeaningCore(rightEntry);
  if (!left.size || !right.length) return true;
  return right.some((value) => left.has(value));
}

function preferDictionaryPrimaryEntry(baseEntry, nextEntry) {
  const basePriority = getDictionaryEntryPriority(baseEntry);
  const nextPriority = getDictionaryEntryPriority(nextEntry);
  if (nextPriority !== basePriority) return nextPriority > basePriority ? nextEntry : baseEntry;
  const baseUpdatedAt = Number(baseEntry?.updatedAt || baseEntry?.fetchedAt) || 0;
  const nextUpdatedAt = Number(nextEntry?.updatedAt || nextEntry?.fetchedAt) || 0;
  if (nextUpdatedAt !== baseUpdatedAt) return nextUpdatedAt > baseUpdatedAt ? nextEntry : baseEntry;
  const baseScore = getDictionaryMeaningCore(baseEntry).length + (String(baseEntry?.explanationUr || "").trim() ? 1 : 0) + (String(baseEntry?.explanationEng || "").trim() ? 1 : 0);
  const nextScore = getDictionaryMeaningCore(nextEntry).length + (String(nextEntry?.explanationUr || "").trim() ? 1 : 0) + (String(nextEntry?.explanationEng || "").trim() ? 1 : 0);
  return nextScore >= baseScore ? nextEntry : baseEntry;
}

function createDictionaryConflictRecord(localRow, remoteRow, mergedEntry) {
  const localEntry = normalizeWordMeaningEntry(localRow?.word || localRow?.normalized, localRow?.payload || {}, {
    defaultOrigins: ["local"],
    defaultSource: localRow?.payload?.source || "local",
  });
  const remoteEntry = normalizeWordMeaningEntry(remoteRow?.word || remoteRow?.normalized, remoteRow?.payload || {}, {
    defaultOrigins: ["remote"],
    defaultSource: remoteRow?.payload?.source || "remote",
  });
  const normalizedWord = String(localRow?.normalized || remoteRow?.normalized || mergedEntry?.normalizedWord || "").trim().toLowerCase();
  if (!normalizedWord || !localEntry || !remoteEntry) return null;
  return {
    id: `${normalizedWord}:${Math.max(Number(localRow?.updatedAt) || 0, Number(remoteRow?.updatedAt) || 0)}`,
    normalizedWord,
    word: mergedEntry?.word || remoteEntry.word || localEntry.word || normalizedWord,
    localEntry,
    remoteEntry,
    mergedEntry: normalizeWordMeaningEntry(mergedEntry?.word || normalizedWord, mergedEntry || {}, {
      defaultOrigins: ["merged"],
      defaultSource: mergedEntry?.source || "merged",
    }),
    localUpdatedAt: Number(localRow?.updatedAt) || 0,
    remoteUpdatedAt: Number(remoteRow?.updatedAt) || 0,
    detectedAt: Date.now(),
  };
}

function sanitizeDictionaryConflictRecords(rawRecords) {
  return (Array.isArray(rawRecords) ? rawRecords : [])
    .map((record) => {
      const normalizedWord = normalizeLookupWord(record?.normalizedWord || record?.word || "");
      if (!normalizedWord) return null;
      const localEntry = normalizeWordMeaningEntry(record?.localEntry?.word || normalizedWord, record?.localEntry || {}, {
        defaultOrigins: ["local"],
        defaultSource: record?.localEntry?.source || "local",
      });
      const remoteEntry = normalizeWordMeaningEntry(record?.remoteEntry?.word || normalizedWord, record?.remoteEntry || {}, {
        defaultOrigins: ["remote"],
        defaultSource: record?.remoteEntry?.source || "remote",
      });
      const mergedEntry = normalizeWordMeaningEntry(record?.mergedEntry?.word || normalizedWord, record?.mergedEntry || {}, {
        defaultOrigins: ["merged"],
        defaultSource: record?.mergedEntry?.source || "merged",
      });
      if (!localEntry || !remoteEntry || !mergedEntry) return null;
      return {
        id: String(record?.id || `${normalizedWord}:${Date.now()}`),
        normalizedWord,
        word: String(record?.word || mergedEntry.word || remoteEntry.word || localEntry.word || normalizedWord),
        localEntry,
        remoteEntry,
        mergedEntry,
        localUpdatedAt: Number(record?.localUpdatedAt) || 0,
        remoteUpdatedAt: Number(record?.remoteUpdatedAt) || 0,
        detectedAt: Number(record?.detectedAt) || Date.now(),
      };
    })
    .filter(Boolean)
    .sort((left, right) => (Number(right.detectedAt) || 0) - (Number(left.detectedAt) || 0))
    .slice(0, 50);
}

function mergeDictionaryConflictRecords(currentRecords, incomingRecords) {
  const merged = new Map();
  sanitizeDictionaryConflictRecords(currentRecords).forEach((record) => {
    merged.set(record.normalizedWord, record);
  });
  sanitizeDictionaryConflictRecords(incomingRecords).forEach((record) => {
    const existing = merged.get(record.normalizedWord);
    if (!existing || (Number(record.detectedAt) || 0) >= (Number(existing.detectedAt) || 0)) {
      merged.set(record.normalizedWord, record);
    }
  });
  return Array.from(merged.values())
    .sort((left, right) => (Number(right.detectedAt) || 0) - (Number(left.detectedAt) || 0))
    .slice(0, 50);
}

function buildCompactWordMeaningState(rawCache, limit = 80) {
  return Object.entries(normalizeWordMeaningCache(rawCache || {}))
    .sort((left, right) => ((right[1]?.updatedAt || right[1]?.fetchedAt || 0) - (left[1]?.updatedAt || left[1]?.fetchedAt || 0)))
    .slice(0, limit)
    .reduce((acc, [key, value]) => {
      acc[key] = value;
      return acc;
    }, {});
}

function normalizeDictionaryImportPayload(rawPayload, options = {}) {
  if (!rawPayload) return {};
  if (Array.isArray(rawPayload)) {
    return normalizeWordMeaningCache(rawPayload, options);
  }
  if (rawPayload && typeof rawPayload === "object") {
    if (rawPayload.appState?.wordMeaningCache) {
      return normalizeWordMeaningCache(rawPayload.appState.wordMeaningCache, options);
    }
    if (Array.isArray(rawPayload.dbProgress?.customizations)) {
      const dictionaryRow = rawPayload.dbProgress.customizations.find((row) => row?.type === "wordMeaningCache");
      if (dictionaryRow?.data) {
        return normalizeWordMeaningCache(dictionaryRow.data, options);
      }
    }
    if (Array.isArray(rawPayload.entries)) {
      return normalizeWordMeaningCache(rawPayload.entries, options);
    }
    if (rawPayload.dictionary && typeof rawPayload.dictionary === "object") {
      return normalizeWordMeaningCache(rawPayload.dictionary, options);
    }
    return normalizeWordMeaningCache(rawPayload, options);
  }
  return {};
}

