function getSupabaseAuthRedirectUrl() {
  if (typeof location === "undefined" || location.protocol === "file:") return undefined;
  return `${location.origin}${location.pathname}${location.search}`;
}

function getSupabaseUserRole(user) {
  const role = String(
    user?.app_metadata?.homeschoolRole
    || user?.app_metadata?.contentRole
    || user?.app_metadata?.role
    || user?.user_metadata?.homeschoolRole
    || user?.user_metadata?.contentRole
    || user?.user_metadata?.role
    || "student",
  ).trim().toLowerCase();
  return role || "student";
}

