    {[
      "Green = Muslim majority",
      "White = Religious minorities",
      "Crescent = Progress",
      "Star = Light & knowledge",
    ].map((t, i) => <text key={i} x="18" y={196+i*14} fill="#64748B" fontSize="9.5" fontFamily="'Baloo 2'">{t}</text>)}
