  const copyTextToClipboard = useCallback(async (text) => {
    const payload = String(text || "");
    if (!payload.trim()) return false;
    try {
      if (navigator.clipboard?.writeText) {
        await navigator.clipboard.writeText(payload);
        showAppToast(joinLocalizedText("Copied", "کاپی ہو گیا", language), "copy");
        return true;
      }
    } catch (error) {
      // Fall through to manual copy.
    }
    try {
      const helper = document.createElement("textarea");
      helper.value = payload;
      helper.setAttribute("readonly", "readonly");
      helper.style.position = "fixed";
      helper.style.opacity = "0";
      document.body.appendChild(helper);
      helper.select();
      document.execCommand("copy");
      document.body.removeChild(helper);
      showAppToast(joinLocalizedText("Copied", "کاپی ہو گیا", language), "copy");
      return true;
    } catch (error) {
      return false;
    }
  }, [language, showAppToast]);

  const speakInlineText = useCallback((text, languageHint = null) => {
    const content = String(text || "").trim();
    if (!content) return;
    const detectedLanguage = languageHint || (containsUrduText(content) || isUrduText(content) ? "ur" : "en");
    window.HomeSchoolUtils?.speakText?.(content, detectedLanguage);
  }, []);

  const playDiaryAudioSequence = useCallback((segments = []) => {
    const lines = (Array.isArray(segments) ? segments : [])
      .map((entry) => String(entry || "").trim())
      .filter(Boolean);
    if (!lines.length || !isTtsEnabled()) return;
    window.speechSynthesis.cancel();
    let index = 0;
    const speakNext = () => {
      if (index >= lines.length) return;
      const line = lines[index];
      const lang = containsUrduText(line) || isUrduText(line) ? "ur" : "en";
      const utterance = window.HomeSchoolUtils?.speakText?.(line, lang) || null;
      if (!utterance) return;
      utterance.onend = () => {
        index += 1;
        speakNext();
      };
      utterance.onerror = () => {
        index += 1;
        speakNext();
      };
    };
    speakNext();
  }, []);

